import React, { useState } from "react";
import { Provider } from "@supabase/supabase-js";
import { useTranslation } from "react-i18next";
import { AUTH_RETURN_PATH_KEY, beginAccountLink, getOAuthCallbackUrl, useAuthSession } from "../../hooks/useAuthSession";
import { useReviewerAccess } from "../../hooks/useReviewerAccess";
import { supabase } from "../../tools/supabaseClient";
import { DiscordIconSVG } from "../svg/DiscordIcon";
import "./HeaderAuthButtons.css";

type Props = { inline?: boolean };
type OAuthProvider = "google" | "discord";

export const HeaderAuthButtons: React.FC<Props> = ({ inline = false }) => {
  const { i18n } = useTranslation();
  const ru = i18n.language === "ru";
  const { session, user, loading } = useAuthSession();
  const { isReviewer, reconnectRequired } = useReviewerAccess();
  const [working, setWorking] = useState<Provider | "signout" | null>(null);
  const provider = user?.app_metadata?.provider as Provider | undefined;
  const linkedProviders = new Set((user?.identities || []).map(identity => identity.provider));

  const oauthOptions = (nextProvider: OAuthProvider) => ({
    redirectTo: getOAuthCallbackUrl(),
    scopes: nextProvider === "discord" ? "identify email guilds.members.read" : undefined,
    queryParams: nextProvider === "discord" ? { prompt: "consent" } : undefined
  });

  const signInOrLink = async (nextProvider: OAuthProvider) => {
    if (nextProvider === "discord" && user && linkedProviders.has("discord") && reconnectRequired) {
      setWorking(nextProvider);
      sessionStorage.setItem(AUTH_RETURN_PATH_KEY, window.location.pathname);
      const { error: signOutError } = await supabase.auth.signOut({ scope: "local" });
      if (signOutError) {
        setWorking(null);
        window.alert(signOutError.message);
        return;
      }
      const { error } = await supabase.auth.signInWithOAuth({ provider: nextProvider, options: oauthOptions(nextProvider) });
      if (error) {
        sessionStorage.removeItem(AUTH_RETURN_PATH_KEY);
        setWorking(null);
        window.alert(error.message);
      }
      return;
    }

    if (provider === nextProvider) {
      setWorking("signout");
      await supabase.auth.signOut();
      setWorking(null);
      return;
    }

    if (user && linkedProviders.has(nextProvider)) {
      window.alert(ru ? "Этот аккаунт уже привязан." : "This account is already linked.");
      return;
    }

    setWorking(nextProvider);
    sessionStorage.setItem(AUTH_RETURN_PATH_KEY, window.location.pathname);
    const { error } = user && session
      ? await beginAccountLink(session, nextProvider, oauthOptions(nextProvider).redirectTo)
      : await supabase.auth.signInWithOAuth({ provider: nextProvider, options: oauthOptions(nextProvider) });
    if (error) {
      sessionStorage.removeItem(AUTH_RETURN_PATH_KEY);
      setWorking(null);
      window.alert(error.message);
    }
  };

  const title = (nextProvider: OAuthProvider) => {
    const providerName = nextProvider === "discord" ? "Discord" : "Google";
    if (nextProvider === "discord" && reconnectRequired) return ru ? "Переподключить Discord для проверки ролей" : "Reconnect Discord to verify roles";
    if (provider === nextProvider) return ru ? "Выйти из аккаунта" : "Sign out";
    if (linkedProviders.has(nextProvider)) return ru ? `${providerName} привязан` : `${providerName} linked`;
    if (user) return ru ? `Привязать ${providerName}` : `Link ${providerName}`;
    return ru ? `Войти через ${providerName}` : `Sign in with ${providerName}`;
  };

  return (
    <div className={`compact-auth-buttons ${inline ? "inline" : "header"}`} aria-label={ru ? "Вход в аккаунт" : "Account sign in"}>
      <button
        type="button"
        className={`compact-auth-button google ${linkedProviders.has("google") ? "linked" : ""} ${provider === "google" ? "active" : ""}`}
        onClick={() => signInOrLink("google")}
        disabled={loading || working !== null}
        title={title("google")}
        aria-label={title("google")}
      >
        <span>G</span>
      </button>
      <button
        type="button"
        className={`compact-auth-button discord ${linkedProviders.has("discord") ? "linked" : ""} ${provider === "discord" ? "active" : ""} ${isReviewer ? "reviewer" : ""}`}
        onClick={() => signInOrLink("discord")}
        disabled={loading || working !== null}
        title={title("discord")}
        aria-label={title("discord")}
      >
        <DiscordIconSVG />
      </button>
    </div>
  );
};
