import React, { useCallback, useEffect, useMemo, useState } from "react";
import { useTranslation } from "react-i18next";
import { useDispatch } from "react-redux";
import { useQueryClient } from "react-query";
import { User } from "@supabase/supabase-js";
import { tbSetSlotsAction } from "../../../store/reducers/tb-reducer";
import { supabase } from "../../../tools/supabaseClient";
import { decodeFormationCode } from "../tb-slots/tb-utils";
import { CollapsibleSection } from "./CollapsibleSection";
import { CommunityTeamCard } from "./CommunityTeamCard";
import { StatusAutocomplete } from "./StatusAutocomplete";
import { TeamEditForm } from "./TeamEditForm";
import { getTeamStatusOptions } from "./status-utils";
import { TEAM_CONTENT_TYPES, TeamContentType, TeamPreset, TeamVote, getLocalizedTeamText } from "./team-types";

type Props = { user?: User; refreshKey: number };
type SortMode = "likes" | "dislikes" | "rating" | "newest";
const PAGE_SIZE = 1000;

const getStatuses = (team: TeamPreset) => {
  if (Array.isArray(team.statuses)) return team.statuses;
  try { return JSON.parse(team.statuses as unknown as string) as string[]; } catch { return []; }
};

const loadPublicTeams = async (columns: string) => {
  const teams: TeamPreset[] = [];
  for (let from = 0; ; from += PAGE_SIZE) {
    const { data, error } = await supabase
      .from("team_presets")
      .select(columns)
      .eq("is_public", true)
      .eq("moderation_status", "approved")
      .order("created_at", { ascending: false })
      .range(from, from + PAGE_SIZE - 1);
    if (error) return { data: teams, error };
    teams.push(...((data || []) as unknown as TeamPreset[]));
    if (!data || data.length < PAGE_SIZE) return { data: teams, error: null };
  }
};

export const CommunityTeams: React.FC<Props> = ({ user, refreshKey }) => {
  const { i18n } = useTranslation();
  const ru = i18n.language === "ru";
  const dispatch = useDispatch();
  const queryClient = useQueryClient();
  const [publicTeams, setPublicTeams] = useState<TeamPreset[]>([]);
  const [myTeams, setMyTeams] = useState<TeamPreset[]>([]);
  const [userVotes, setUserVotes] = useState<Record<string, TeamVote>>({});
  const [search, setSearch] = useState("");
  const [statusFilters, setStatusFilters] = useState<string[]>([]);
  const [sort, setSort] = useState<SortMode>("likes");
  const [contentType, setContentType] = useState<TeamContentType | "all">("all");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [editingTeam, setEditingTeam] = useState<TeamPreset | null>(null);
  const columns = "id,user_id,author_name,author_avatar_url,title,title_ru,title_en,description,description_ru,description_en,is_public,content_type,youtube_url,team_code,lineup,slot_roles,statuses,main_status,background_status,recommended_gifts,moderation_status,moderation_note,likes_count,dislikes_count,created_at";

  const statusOptions = useMemo(() => getTeamStatusOptions(
    queryClient.getQueryData<any[]>("statuses") || [],
    ru,
    queryClient.getQueryData<any[]>("identities") || []
  ), [queryClient, ru]);

  const loadTeams = useCallback(async () => {
    setLoading(true);
    setError("");
    const [publicResult, ownResult] = await Promise.all([
      loadPublicTeams(columns),
      user ? supabase.from("team_presets").select(columns).eq("user_id", user.id).order("created_at", { ascending: false }).limit(50) : Promise.resolve({ data: [], error: null })
    ]);
    if (publicResult.error || ownResult.error) setError(publicResult.error?.message || ownResult.error?.message || "Error");
    const publicData = (publicResult.data || []) as TeamPreset[];
    setPublicTeams(publicData);
    setMyTeams((ownResult.data || []) as TeamPreset[]);

    if (user && publicData.length) {
      const { data: votes, error: votesError } = await supabase.from("team_votes").select("team_id,vote").in("team_id", publicData.map(team => team.id));
      if (votesError) setError(votesError.message);
      else setUserVotes(Object.fromEntries((votes || []).map(item => [item.team_id, item.vote as TeamVote])));
    } else setUserVotes({});
    setLoading(false);
  }, [user, columns]);

  useEffect(() => { loadTeams(); }, [loadTeams, refreshKey]);
  useEffect(() => {
    const refresh = () => loadTeams();
    window.addEventListener("gll-profile-updated", refresh);
    return () => window.removeEventListener("gll-profile-updated", refresh);
  }, [loadTeams]);

  const loadTeam = async (team: TeamPreset) => {
    try {
      const slots = await decodeFormationCode(team.team_code, queryClient);
      const roles = Array.isArray(team.slot_roles) ? team.slot_roles : [];
      tbSetSlotsAction(dispatch, { slots: slots.map((slot, index) => ({ ...slot, role: roles[index] === "support" ? "support" : "combat" })) });
      window.scrollTo({ top: 0, behavior: "smooth" });
    } catch {
      setError(ru ? "Не удалось прочитать код этой команды." : "Could not decode this team.");
    }
  };

  const deleteTeam = async (team: TeamPreset) => {
    const title = getLocalizedTeamText(team, "title", ru);
    if (!window.confirm(ru ? `Удалить «${title}»?` : `Delete “${title}”?`)) return;
    const { error: deleteError } = await supabase.from("team_presets").delete().eq("id", team.id);
    if (deleteError) setError(deleteError.message);
    else loadTeams();
  };

  const vote = async (team: TeamPreset, requestedVote: TeamVote) => {
    if (!user || team.user_id === user.id) return;
    const previousVote = userVotes[team.id] || null;
    const nextVote = previousVote === requestedVote ? null : requestedVote;
    const applyVote = (items: TeamPreset[]) => items.map(item => item.id !== team.id ? item : {
      ...item,
      likes_count: Math.max(0, (item.likes_count || 0) + (previousVote === 1 ? -1 : 0) + (nextVote === 1 ? 1 : 0)),
      dislikes_count: Math.max(0, (item.dislikes_count || 0) + (previousVote === -1 ? -1 : 0) + (nextVote === -1 ? 1 : 0))
    });
    setPublicTeams(applyVote);
    setUserVotes(current => {
      const next = { ...current };
      if (nextVote) next[team.id] = nextVote;
      else delete next[team.id];
      return next;
    });

    const result = nextVote
      ? await supabase.from("team_votes").upsert({ team_id: team.id, user_id: user.id, vote: nextVote }, { onConflict: "team_id,user_id" })
      : await supabase.from("team_votes").delete().eq("team_id", team.id).eq("user_id", user.id);
    if (result.error) {
      setError(result.error.message);
      loadTeams();
    }
  };

  const filtered = useMemo(() => {
    const query = search.trim().toLocaleLowerCase();
    return publicTeams
      .filter(team => !query || JSON.stringify([team.title, team.title_ru, team.title_en, team.description, team.description_ru, team.description_en, team.author_name, team.main_status, team.statuses, team.lineup]).toLocaleLowerCase().includes(query))
      .filter(team => statusFilters.every(status => getStatuses(team).includes(status)))
      .filter(team => contentType === "all" || team.content_type === contentType)
      .sort((a, b) => {
        if (sort === "dislikes") return (b.dislikes_count || 0) - (a.dislikes_count || 0);
        if (sort === "rating") return ((b.likes_count || 0) - (b.dislikes_count || 0)) - ((a.likes_count || 0) - (a.dislikes_count || 0));
        if (sort === "newest") return new Date(b.created_at).getTime() - new Date(a.created_at).getTime();
        return (b.likes_count || 0) - (a.likes_count || 0) || new Date(b.created_at).getTime() - new Date(a.created_at).getTime();
      });
  }, [publicTeams, search, sort, statusFilters, contentType]);

  const cardProps = (team: TeamPreset) => ({
    userVote: userVotes[team.id] || null,
    canVote: !!user && team.user_id !== user.id,
    onVote: user ? vote : undefined
  });

  return (
    <section className="community-teams">
      {user && <CollapsibleSection storageKey="my-teams" kicker="PRIVATE" title={ru ? "Мои команды" : "My teams"} badge={myTeams.length} className="community-team-section" collapsible>
        {myTeams.length ? <div className="community-team-grid">{myTeams.map(team => <CommunityTeamCard key={team.id} team={team} onLoad={loadTeam} onEdit={setEditingTeam} onDelete={deleteTeam} showModeration {...cardProps(team)} />)}</div> : <div className="community-empty">{ru ? "Сохранённых команд пока нет." : "No saved teams yet."}</div>}
      </CollapsibleSection>}

      <CollapsibleSection storageKey="community-teams" kicker="APPROVED" title={ru ? "Команды игроков" : "Community teams"} badge={publicTeams.length} className="community-team-section" collapsible>
        <div className="community-team-filters">
          <label className="community-team-search"><span>⌕</span><input value={search} onChange={event => setSearch(event.target.value)} placeholder={ru ? "Название, статус, личность…" : "Title, status, Identity…"} /></label>
          <label className="community-sort"><span className="visually-hidden">{ru ? "Сортировка" : "Sort"}</span><select aria-label={ru ? "Сортировка" : "Sort"} value={sort} onChange={event => setSort(event.target.value as SortMode)}><option value="likes">{ru ? "Больше лайков" : "Most liked"}</option><option value="rating">{ru ? "Лучший рейтинг" : "Best rating"}</option><option value="dislikes">{ru ? "Больше дизлайков" : "Most disliked"}</option><option value="newest">{ru ? "Сначала новые" : "Newest"}</option></select></label>
          <label className="community-sort community-content-filter"><span className="visually-hidden">{ru ? "Тип контента" : "Content type"}</span><select value={contentType} onChange={event => setContentType(event.target.value as TeamContentType | "all")}><option value="all">{ru ? "Все режимы" : "All modes"}</option>{TEAM_CONTENT_TYPES.map(option => <option value={option.value} key={option.value}>{ru ? option.ru : option.en}</option>)}</select></label>
          <div className="community-status-filter"><StatusAutocomplete options={statusOptions} selected={statusFilters} onChange={setStatusFilters} placeholder={ru ? "Фильтр тегов: начните писать…" : "Tag filter: start typing…"} noResults={ru ? "Подходящих тегов нет" : "No matching tags"} limit={6} /></div>
        </div>
        
        {loading ? <div className="community-empty">{ru ? "Загрузка…" : "Loading…"}</div> : filtered.length ? <div className="community-team-grid">{filtered.map(team => <CommunityTeamCard key={team.id} team={team} onLoad={loadTeam} {...cardProps(team)} />)}</div> : <div className="community-empty">{ru ? "Команды по этим фильтрам не найдены." : "No teams match these filters."}</div>}
      </CollapsibleSection>
      {editingTeam && <TeamEditForm key={editingTeam.id} team={editingTeam} statusOptions={statusOptions} onClose={() => setEditingTeam(null)} onSaved={() => { setEditingTeam(null); loadTeams(); }} />}
    </section>
  );
};
