import React, { useMemo, useState } from "react";
import { TeamStatusOption } from "./status-utils";

type Props = {
  options: TeamStatusOption[];
  selected: string[];
  onChange: (next: string[]) => void;
  placeholder: string;
  mainStatus?: string;
  onMainChange?: (value: string) => void;
  limit?: number;
  noResults: string;
  mainTitle?: string;
};

export const StatusAutocomplete: React.FC<Props> = ({ options, selected, onChange, placeholder, mainStatus, onMainChange, limit = 8, noResults, mainTitle }) => {
  const [query, setQuery] = useState("");
  const suggestions = useMemo(() => {
    const normalized = query.trim().toLocaleLowerCase();
    if (!normalized) return [];
    return options.filter(option => !selected.includes(option.value) && option.search.includes(normalized)).slice(0, 8);
  }, [options, query, selected]);
  const getLabel = (value: string) => options.find(option => option.value === value)?.label || value;

  const add = (value: string) => {
    if (selected.length >= limit || selected.includes(value)) return;
    onChange([...selected, value]);
    setQuery("");
  };

  const remove = (value: string) => onChange(selected.filter(status => status !== value));

  return (
    <div className="status-autocomplete">
      <div className="status-autocomplete-input-wrap">
        <span>⌕</span>
        <input value={query} onChange={event => setQuery(event.target.value)} placeholder={placeholder} autoComplete="off" />
      </div>
      {!!suggestions.length && <div className="status-autocomplete-suggestions">{suggestions.map(option => <button type="button" className={option.value.startsWith("trait:") ? "is-trait" : ""} key={option.value} onClick={() => add(option.value)}><strong>{option.label}</strong><small>{option.value.startsWith("trait:") ? "TRAIT" : option.value}</small></button>)}</div>}
      {!!query.trim() && !suggestions.length && <div className="status-autocomplete-empty">{noResults}</div>}
      {!!selected.length && <div className="status-autocomplete-selected">{selected.map(value => <div className={`status-autocomplete-chip ${value.startsWith("trait:") ? "is-trait" : ""} ${mainStatus === value ? "is-main" : ""}`} key={value}>
        {onMainChange && <button type="button" className="status-autocomplete-star" onClick={() => onMainChange(value)} title={mainTitle}>★</button>}
        <span>{getLabel(value)}</span>
        <button type="button" className="status-autocomplete-remove" onClick={() => remove(value)} aria-label={`Remove ${getLabel(value)}`}>×</button>
      </div>)}</div>}
    </div>
  );
};
