import type React from "react";

export const getIdentityImageUrl = (imgUrl: string, variant: 1 | 2 = 1) =>
  `${process.env.PUBLIC_URL}/images/identities/${imgUrl}.${variant}.webp`;

export const handleIdentityImageError = (
  event: React.SyntheticEvent<HTMLImageElement>,
  imgUrl: string,
  tryBaseVariant = false
) => {
  const image = event.currentTarget;
  if (tryBaseVariant && image.dataset.identityFallback !== "base") {
    image.dataset.identityFallback = "base";
    image.src = getIdentityImageUrl(imgUrl);
    return;
  }
  if (image.dataset.identityFallback === "profile") return;
  image.dataset.identityFallback = "profile";
  image.src = `${process.env.PUBLIC_URL}/images/identities-profiles/${imgUrl}.1_profile.webp`;
};
