import React, { useEffect, useRef, useState } from "react";
import { useTranslation } from "react-i18next";
import { useLocation, useNavigate } from "react-router-dom";
import { locales } from "../../constants/locales";
import { GlobeSVG } from "../svg/GlobeSVG";
import { GoogleTranslateSVG } from "../svg/GoogleTranslate";
import "./LanguageSelect.css";

interface LanguageSelectProps {
    compact?: boolean;
}

export const LanguageSelect: React.FC<LanguageSelectProps> = ({ compact = false }) => {
    const [isOpen, setIsOpen] = useState(false);
    const containerRef = useRef<HTMLDivElement>(null);
    const navigate = useNavigate();
    const location = useLocation();
    const routeLanguage = location.pathname.match(/^\/(?:limbus|umamusume)\/(ru|en)(?:\/|$)/)?.[1];
    const { i18n } = useTranslation();
    const game = location.pathname.split("/")[1] || "limbus";
    const currentLocale = locales.find(locale => locale.locale === i18n.language) || locales[0];

    useEffect(() => {
        const handleOutsideClick = (event: PointerEvent) => {
            if (!containerRef.current?.contains(event.target as Node)) setIsOpen(false);
        };

        document.addEventListener("pointerdown", handleOutsideClick);
        return () => document.removeEventListener("pointerdown", handleOutsideClick);
    }, []);

    useEffect(() => {
        const storedLanguage = localStorage.getItem("i18nextLng") || "";
        const fallbackLanguage = locales.some(locale => locale.locale === storedLanguage)
            ? storedLanguage
            : "en";

        if (!routeLanguage && ["/limbus", "/umamusume"].some(path => location.pathname.startsWith(path))) {
            void i18n.changeLanguage(fallbackLanguage);
            navigate(`/${game}/${fallbackLanguage}/`, { replace: true });
            return;
        }

        const language = locales.some(locale => locale.locale === routeLanguage)
            ? routeLanguage
            : "en";
        void i18n.changeLanguage(language);
    }, [game, i18n, location.pathname, navigate, routeLanguage]);

    const changeLanguage = (locale: string) => {
        const language = locales.some(item => item.locale === locale) ? locale : "en";
        const parts = location.pathname.split("/");
        const remainingPath = parts.length > 3 ? `/${parts.slice(3).join("/")}` : "/";

        void i18n.changeLanguage(language);
        navigate(`/${game}/${language}${remainingPath}`);
        setIsOpen(false);
    };

    return (
        <div
            ref={containerRef}
            className={`language-select ${compact ? "language-select--compact" : ""}`}
        >
            <button
                type="button"
                className="language-select-trigger"
                onClick={() => setIsOpen(value => !value)}
                aria-haspopup="listbox"
                aria-expanded={isOpen}
                aria-label={currentLocale?.name || i18n.language}
                title={compact ? currentLocale?.name : undefined}
            >
                <span className="language-select-icon"><GlobeSVG /></span>
                <span className="language-select-label">{currentLocale?.name}</span>
                <span className="language-select-caret" aria-hidden="true" />
            </button>

            {isOpen && (
                <ul className="language-select-options" role="listbox">
                    {locales.map(({ locale, name, isAutoTranslated }) => (
                        <li key={locale} role="option" aria-selected={locale === i18n.language}>
                            <button type="button" onClick={() => changeLanguage(locale)}>
                                <span>{name}</span>
                                {isAutoTranslated && <GoogleTranslateSVG />}
                            </button>
                        </li>
                    ))}
                </ul>
            )}
        </div>
    );
};
