import React, { useEffect, useMemo } from "react";
import { SlotInterface } from "../../../store/reducers/tb-reducer";
import { handleIdentityImageError } from "../../../tools/identityImage";

type Props = {
  slots: SlotInterface[];
  orders: Record<number, number>;
  onChange: (orders: Record<number, number>) => void;
  ru: boolean;
};

export const BattleOrderSelector: React.FC<Props> = ({ slots, orders, onChange, ru }) => {
  const combatSlots = useMemo(() => slots.map((slot, index) => ({ slot, index })).filter(({ slot }) => slot.identity && slot.role !== "support"), [slots]);
  const supportSlots = useMemo(() => slots.map((slot, index) => ({ slot, index })).filter(({ slot }) => slot.identity && slot.role === "support"), [slots]);

  useEffect(() => {
    const used = new Set<number>();
    const next: Record<number, number> = Object.fromEntries(supportSlots
      .filter(({ index }) => Number(orders[index]) >= 8 && Number(orders[index]) <= 12)
      .map(({ index }) => [index, Number(orders[index])]));
    combatSlots.forEach(({ slot, index }) => {
      const stored = Number(orders[index] || slot.teamCodeSlotType);
      if (Number.isInteger(stored) && stored > 0 && stored <= combatSlots.length && !used.has(stored)) {
        next[index] = stored;
        used.add(stored);
      }
    });
    combatSlots.forEach(({ index }) => {
      if (next[index]) return;
      let value = 1;
      while (used.has(value)) value++;
      next[index] = value;
      used.add(value);
    });
    if (JSON.stringify(next) !== JSON.stringify(orders)) onChange(next);
  }, [combatSlots, supportSlots, orders, onChange]);

  if (!combatSlots.length && !supportSlots.length) return null;

  return (
    <div className="team-battle-order team-preset-field--wide">
      <div><strong>{ru ? "Порядок выхода на поле" : "Deployment order"}</strong><small>{ru ? "Укажите, кто выходит 1-м, 2-м и далее." : "Choose who deploys 1st, 2nd, and so on."}</small></div>
      {!!combatSlots.length && <div className="team-battle-order-list">
        {combatSlots.map(({ slot, index }) => (
          <label key={index}>
            <img src={`/images/identities/${slot.identity?.imgUrl}.1.webp`} onError={event => handleIdentityImageError(event, slot.identity!.imgUrl)} alt="" />
            <select value={orders[index] || ""} onChange={event => {
              const value = Number(event.target.value);
              const swappedIndex = Number(Object.keys(orders).find(key => orders[Number(key)] === value));
              const next = { ...orders, [index]: value };
              if (Number.isInteger(swappedIndex) && swappedIndex !== index) next[swappedIndex] = orders[index];
              onChange(next);
            }}>
              {combatSlots.map((_, orderIndex) => <option value={orderIndex + 1} key={orderIndex + 1}>{orderIndex + 1}</option>)}
            </select>
          </label>
        ))}
      </div>}
      {!!supportSlots.length && <><div className="team-support-order-title"><strong>{ru ? "Порядок поддержки" : "Support order"}</strong><small>{ru ? "Необязательно: номера 8–12." : "Optional: positions 8–12."}</small></div><div className="team-battle-order-list team-battle-order-list--support">
        {supportSlots.map(({ slot, index }) => (
          <label key={index}>
            <img src={`/images/identities/${slot.identity?.imgUrl}.1.webp`} onError={event => handleIdentityImageError(event, slot.identity!.imgUrl)} alt="" />
            <select value={orders[index] || ""} onChange={event => {
              const value = Number(event.target.value);
              const next = { ...orders };
              if (!value) delete next[index];
              else {
                const swappedIndex = Object.keys(next).map(Number).find(key => key !== index && next[key] === value);
                if (swappedIndex !== undefined) delete next[swappedIndex];
                next[index] = value;
              }
              onChange(next);
            }}>
              <option value="">—</option>
              {[8, 9, 10, 11, 12].map(value => <option value={value} key={value}>{value}</option>)}
            </select>
          </label>
        ))}
      </div></>}
    </div>
  );
};
