export const getLocalizedTeamText = (team: TeamPreset, field: "title" | "description", ru: boolean) => {
  const primary = team[`${field}_${ru ? "ru" : "en"}` as keyof TeamPreset];
  const secondary = team[`${field}_${ru ? "en" : "ru"}` as keyof TeamPreset];
  return String(primary || secondary || team[field] || "");
};

export const applyBattleOrder = <T extends { role?: "combat" | "support"; identity?: unknown; teamCodeSlotType?: number }>(slots: T[], orders: Record<number, number>) => (
  slots.map((slot, index) => ({
    ...slot,
    teamCodeSlotType: slot.role === "support" || !slot.identity ? 0 : orders[index]
  }))
);

export const getYoutubeVideoId = (url?: string | null) => {
  if (!url) return null;
  try {
    const parsed = new URL(url);
    let videoId: string | null = null;
    if (parsed.hostname === "youtu.be") videoId = parsed.pathname.split("/").filter(Boolean)[0] || null;
    if (parsed.hostname.endsWith("youtube.com")) {
      if (parsed.pathname === "/watch") videoId = parsed.searchParams.get("v");
      const parts = parsed.pathname.split("/").filter(Boolean);
      if (["embed", "shorts", "live"].includes(parts[0])) videoId = parts[1] || null;
    }
    return videoId && /^[a-zA-Z0-9_-]{6,15}$/.test(videoId) ? videoId : null;
  } catch {
    return null;
  }
};
