import React, { useEffect, useMemo, useState } from "react";
import { createPortal } from "react-dom";
import { useQueryClient } from "react-query";
import { MDGift } from "../../../store/reducers/md-gift-interface";
import { extractInlineTraits } from "../../entity-full-info/traits";
import { FilterButton } from "../../filters/filter-button/FilterButton";
import "./TeamGiftSelector.css";

type Props = {
  selected: string[];
  onChange?: (selected: string[]) => void;
  ru: boolean;
  viewOnly?: boolean;
};

const tierLabels: Record<number, string> = { 1: "I", 2: "II", 3: "III", 4: "IV", 5: "V", 6: "EX" };

const parseSelected = (value: unknown): string[] => {
  if (Array.isArray(value)) return value.filter((item): item is string => typeof item === "string");
  if (typeof value !== "string") return [];
  try { return parseSelected(JSON.parse(value)); } catch { return []; }
};

export const getTeamGiftIds = parseSelected;

export const TeamGiftSelector: React.FC<Props> = ({ selected, onChange, ru, viewOnly = false }) => {
  const queryClient = useQueryClient();
  const gifts = (queryClient.getQueryData<MDGift[]>("md-gifts") || []).filter(gift => gift.id !== "gift_0");
  const [open, setOpen] = useState(false);
  const [search, setSearch] = useState("");
  const [tier, setTier] = useState("all");
  const [sin, setSin] = useState("all");
  const [keyword, setKeyword] = useState("all");

  useEffect(() => {
    if (!open) return;
    const previousOverflow = document.body.style.overflow;
    document.body.style.overflow = "hidden";
    const close = (event: KeyboardEvent) => event.key === "Escape" && setOpen(false);
    window.addEventListener("keydown", close);
    return () => {
      document.body.style.overflow = previousOverflow;
      window.removeEventListener("keydown", close);
    };
  }, [open]);

  const keywords = useMemo(() => Array.from(new Set(gifts.map(gift => gift.keyword).filter(value => value && value !== "none"))).sort(), [gifts]);
  const sins = useMemo(() => Array.from(new Set(gifts.map(gift => gift.sin).filter(Boolean))).sort(), [gifts]);
  const selectedSet = useMemo(() => new Set(selected), [selected]);
  const normalizedSearch = search.trim().toLocaleLowerCase();
  const filtered = gifts.filter(gift => {
    const giftTraits = [...extractInlineTraits(gift), ...(gift.keyword && gift.keyword !== "none" ? [gift.keyword] : [])];
    const localizedName = ru ? gift.nameRU || gift.nameEN : gift.nameEN || gift.nameRU;
    const text = [gift.id, localizedName, gift.nameEN, gift.nameRU, gift.keyword, ...giftTraits].join(" ").toLocaleLowerCase();
    return (!normalizedSearch || text.includes(normalizedSearch))
      && (tier === "all" || String(gift.tier) === tier)
      && (sin === "all" || gift.sin === sin)
      && (keyword === "all" || gift.keyword === keyword);
  });

  const toggle = (giftId: string) => {
    if (!onChange || viewOnly) return;
    onChange(selectedSet.has(giftId) ? selected.filter(id => id !== giftId) : [...selected, giftId]);
  };

  const resetFilters = () => {
    setSearch("");
    setTier("all");
    setSin("all");
    setKeyword("all");
  };

  const modal = open ? createPortal(
    <div className="team-gift-overlay" role="dialog" aria-modal="true" aria-label={ru ? "Выбор рекомендуемых E.G.O-даров" : "Select recommended E.G.O Gifts"} onMouseDown={event => event.target === event.currentTarget && setOpen(false)}>
      <section className={`team-gift-modal${viewOnly ? " team-gift-modal--view" : ""}`}>
        

        {!viewOnly && <div className="team-gift-filters">
          <div className="team-gift-filter-toolbar filters-traits-controls"><input value={search} onChange={event => setSearch(event.target.value)} placeholder={ru ? "Название, эффект или трейт…" : "Name, effect or trait…"} autoFocus /><button type="button" className="filters-traits-toggle" onClick={resetFilters}>{ru ? "Сбросить" : "Reset"}</button></div>
          <div className="team-gift-filter-panel filters filters--mirror-dungeon filters--mirror-dungeon-content">
            <article className="filters-main">
              <section className="filters-section">
                {Object.entries(tierLabels).map(([value, label]) => <FilterButton key={value} type={value} name={`${ru ? "Уровень" : "Tier"} ${label}`} content={label} imgSrc={null} isTypeActive={tier === value} handleFilterChange={() => setTier(tier === value ? "all" : value)} />)}
                <header>{ru ? "Уровень" : "Tier"}</header>
              </section>
              <section className="filters-section">
                {sins.map(value => <FilterButton key={value} type={value} name={value} imgSrc={`${process.env.PUBLIC_URL}/images/sins/${value}.webp`} isTypeActive={sin === value} handleFilterChange={() => setSin(sin === value ? "all" : value)} />)}
                <header>{ru ? "Грех" : "Affinity"}</header>
              </section>
              <section className="filters-section team-gift-effect-filters">
                {keywords.map(value => <FilterButton key={value} type={value} name={value} imgSrc={`${process.env.PUBLIC_URL}/${["blunt", "pierce", "slash"].includes(value) ? "images/dmg-type" : "images/tags"}/${value}.webp`} isTypeActive={keyword === value} handleFilterChange={() => setKeyword(keyword === value ? "all" : value)} />)}
                <header>{ru ? "Эффекты" : "Effects"}</header>
              </section>
            </article>
          </div>
        </div>}

        <div className="team-gift-results">
          {(viewOnly ? gifts.filter(gift => selectedSet.has(gift.id)) : filtered).map(gift => {
            const name = (ru ? gift.nameRU || gift.nameEN : gift.nameEN || gift.nameRU) || gift.id;
            const active = selectedSet.has(gift.id);
            return <button type="button" className={`team-gift-card team-gift-card--${gift.sin}${active ? " is-selected" : ""}`} onClick={() => toggle(gift.id)} key={gift.id} aria-pressed={viewOnly ? undefined : active}>
              <span className="team-gift-image"><img src={`${process.env.PUBLIC_URL}/images/md-gifts/${gift.id}.webp`} alt="" /><b>{tierLabels[gift.tier] || gift.tier}</b>{gift.keyword !== "none" && <img className="team-gift-keyword" src={`${process.env.PUBLIC_URL}/${["blunt", "pierce", "slash"].includes(gift.keyword) ? "images/dmg-type" : "images/tags"}/${gift.keyword}.webp`} alt={gift.keyword} />}{active && !viewOnly && <i>✓</i>}</span>
              <strong title={name}>{name}</strong><small>{gift.keyword !== "none" ? gift.keyword : gift.sin}</small>
            </button>;
          })}
          {!(viewOnly ? selected.length : filtered.length) && <div className="team-gift-empty">{ru ? "Подходящих E.G.O-даров нет." : "No matching E.G.O Gifts."}</div>}
        </div>
        <footer>{!viewOnly && <small>{ru ? "Можно выбрать любое количество. Выбор сохраняется вместе с командой." : "Select any number. The selection is saved with the team."}</small>}<button type="button" onClick={() => setOpen(false)}>{ru ? "Готово" : "Done"}</button></footer>
        </section>
    </div>, document.body
  ) : null;

  return <>
    <button type="button" className={viewOnly ? "community-gifts-button" : "community-load-button team-gift-open"} onClick={() => setOpen(true)}>
      {viewOnly ? (ru ? `Рекомендуемые подарки (${selected.length})` : `Recommended Gifts (${selected.length})`) : (ru ? `Выбрать E.G.O-дары (${selected.length})` : `Select E.G.O Gifts (${selected.length})`)}
    </button>
    {modal}
  </>;
};
