import React, { useMemo, useState } from "react";
import { useTranslation } from "react-i18next";
import { useQueryClient } from "react-query";
import { sinType } from "../../../constants/types";
import { useTypedSelector } from "../../../hooks/useTypedSelector";
import { EGOInterface } from "../../../store/reducers/ego-reducer";
import { IdentityInterface } from "../../../store/reducers/ids-reducer";
import { StatusesInterface } from "../../../store/reducers/statuses-reducer";
import { normalizeTbSin } from "../../../store/reducers/tb-reducer";
import { getStatusesEntityList } from "../../../tools/getStatusesEntityList";
import { handleIdentityImageError } from "../../../tools/identityImage";
import { TbDamage } from "../tb-damage/TbDamage";
import { CollapsibleSection } from "../community/CollapsibleSection";
import "./TbSynergy.css";

const MAIN_KEYWORDS = ["burn", "bleed", "tremor", "rupture", "sinking", "poise", "charge"];
const EGO_RARITIES = ["ZAYIN", "TETH", "HE", "WAW", "ALEPH"];
const STATUS_LABELS: Record<string, string> = {
    burn: "Burn",
    bleed: "Bleed",
    tremor: "Tremor",
    rupture: "Rupture",
    sinking: "Sinking",
    poise: "Poise",
    charge: "Charge",
};
const MAP_SIZE = 360;
const MAP_CENTER = MAP_SIZE / 2;
const MAP_RADIUS = 128;
type MemberSynergy = {
    index: number;
    name: string;
    sinner: string;
    imgUrl: string;
    keywords: string[];
    egoKeywords: string[];
    recommendedIds: string[];
    hasEgoSynergy: boolean;
    supportPassives: PassiveInfo[];
};

type PassiveInfo = {
    sins: sinType[];
    counts: number[];
    condition: string;
    description: string;
};

type PairSynergy = {
    a: MemberSynergy;
    b: MemberSynergy;
    keywords: string[];
    egoKeywords: string[];
    recommended: boolean;
};

type MapNode = MemberSynergy & {
    x: number;
    y: number;
    score: number;
};

const splitStatusUnik = (value?: string | null) => {
    if (!value) return [];
    return value
        .split("|")[0]
        .split(/[,\n;]/)
        .map(item => item.trim())
        .filter(Boolean);
};

const splitReferenceList = (value?: string | null) => {
    if (!value) return [];
    return value
        .split(/[,\n;|]/)
        .map(item => item.trim().toLowerCase())
        .filter(Boolean);
};

const normalizeStatus = (value: string) => value.toLowerCase().replace(/[^\p{L}0-9]+/gu, "");

const STATUS_ALIASES = Object.entries(STATUS_LABELS).reduce<Record<string, string>>((result, [key, label]) => {
    result[normalizeStatus(key)] = key;
    result[normalizeStatus(label)] = key;
    return result;
}, {
    breath: "poise",
    tremorburst: "tremor",
    amplitudeburst: "tremor",
    tremorscorch: "tremor",
    tremorreverb: "tremor",
    tremorhemorrhage: "tremor",
    tremorfracture: "tremor",
    tremordecay: "tremor",
    tremorchain: "tremor",
});

const toAllowedKeyword = (value: string) => STATUS_ALIASES[normalizeStatus(value)];

const getKeywordsFromText = (texts: (string | undefined | null)[]) => {
    return Object.keys(getStatusesEntityList(texts)).map(toAllowedKeyword).filter(Boolean);
};

const getIdentityKeywords = (identity: IdentityInterface) => {
    return sortKeywords([
        ...getKeywordsFromText([
            identity.descriptionCoinEN1,
            identity.descriptionCoinEN2,
            identity.descriptionCoinEN3,
            identity.descriptionCoinEN4,
            identity.descriptionPassive1EN,
            identity.descriptionPassive2EN,
        ]),
        ...splitStatusUnik(identity.statusUnik).map(toAllowedKeyword).filter(Boolean),
    ]);
};

const getSupportKeywords = (identity: IdentityInterface) => {
    return sortKeywords([
        ...getKeywordsFromText([
            identity.descriptionPassive2EN,
        ]),
        ...splitStatusUnik(identity.statusUnik).map(toAllowedKeyword).filter(Boolean),
    ]);
};

const getEgoKeywords = (ego: EGOInterface) => {
    return sortKeywords([
        ...getKeywordsFromText([ego.CoinEN4, ego.descriptionPassiveEN]),
        ...splitStatusUnik(ego.statusUnik).map(toAllowedKeyword).filter(Boolean),
    ]);
};

const getSlotEgos = (egoSlots: Record<string, EGOInterface | null>) => {
    return EGO_RARITIES.map(rarity => egoSlots[rarity]).filter(Boolean) as EGOInterface[];
};

const getMemberName = (identity: IdentityInterface) => {
    const title = identity.nameEN || identity.nameRU || identity.sinner;
    return title.replace(/\s+/g, " ").trim();
};

const getSinnerLabel = (sinner: string) => {
    return sinner
        .split(" ")
        .map(part => part.charAt(0).toUpperCase() + part.slice(1))
        .join(" ");
};

const getPassiveInfo = (identity: IdentityInterface, lang: string): PassiveInfo[] => {
    return [
        {
            sins: identity.sinPassive2 || [],
            counts: identity.countPassive2 || [],
            condition: identity.passive2Condition || "",
            description: lang === "ru" ? identity.descriptionPassive2RU : identity.descriptionPassive2EN,
        },
    ].filter(passive => passive.sins.length || passive.description || passive.condition);
};

const getPassiveConditionKey = (condition: string) => {
    const normalized = condition.toLowerCase();
    if (normalized.includes("res")) return "EntityFullInfoPassive.res";
    return "EntityFullInfoPassive.owned";
};

const getNodePosition = (nodeIndex: number, nodeCount: number) => {
    const angle = -Math.PI / 2 + (Math.PI * 2 * nodeIndex) / nodeCount;
    return {
        x: MAP_CENTER + Math.cos(angle) * MAP_RADIUS,
        y: MAP_CENTER + Math.sin(angle) * MAP_RADIUS,
    };
};

const sortKeywords = (keywords: string[]) => {
    return Array.from(new Set(keywords)).sort((a, b) => {
        const aIndex = MAIN_KEYWORDS.indexOf(a);
        const bIndex = MAIN_KEYWORDS.indexOf(b);
        if (aIndex === -1 && bIndex === -1) return a.localeCompare(b);
        if (aIndex === -1) return 1;
        if (bIndex === -1) return -1;
        return aIndex - bIndex;
    });
};

const DAMAGE_LABELS: Record<string, { en: string; ru: string }> = {
    slash: { en: "Slash", ru: "Slash" },
    pierce: { en: "Pierce", ru: "Pierce" },
    blunt: { en: "Blunt", ru: "Blunt" },
};

const getKeywordLabel = (keyword: string, lang: string, statuses: StatusesInterface[]) => {
    const status = statuses.find(item => item.id === keyword);
    if (status) return lang === "ru" ? status.nameRU || status.nameEN || keyword : status.nameEN || status.nameRU || keyword;
    const damageLabel = DAMAGE_LABELS[keyword];
    if (damageLabel) return lang === "ru" ? damageLabel.ru : damageLabel.en;
    return keyword;
};

const getPairTooltip = (pair: PairSynergy, lang: string, statuses: StatusesInterface[]) => {
    const parts = pair.keywords.map(keyword => getKeywordLabel(keyword, lang, statuses));
    if (pair.egoKeywords.length) {
        parts.push(`E.G.O: ${pair.egoKeywords.map(keyword => getKeywordLabel(keyword, lang, statuses)).join(", ")}`);
    }
    if (pair.recommended) parts.push(lang === "ru" ? "Рекомендованные ID" : "Recommended IDs");
    return parts.join(" | ");
};

export const TbSynergy: React.FC<{ canToggle?: boolean }> = ({ canToggle = true }) => {
    const { slots } = useTypedSelector(store => store.tbReducer);
    const { t, i18n } = useTranslation();
    const statuses = (useQueryClient().getQueryData("statuses") as StatusesInterface[] | undefined) || [];
    const [hoveredPair, setHoveredPair] = useState<PairSynergy | null>(null);
    const [hoveredMemberIndex, setHoveredMemberIndex] = useState<number | null>(null);
    const lang = i18n.language;

    const { combatMembers, supportMembers } = useMemo(() => {
        return slots.reduce<{ combatMembers: MemberSynergy[]; supportMembers: MemberSynergy[] }>((result, slot, index) => {
            if (!slot.identity) return result;
            const isSupport = slot.role === "support";
            const identityKeywords = isSupport ? getSupportKeywords(slot.identity) : getIdentityKeywords(slot.identity);
            const egos = isSupport ? [] : getSlotEgos(slot.ego);
            const identityReferences = splitReferenceList(slot.identity.synEGO);
            const egoReferences = egos.flatMap(ego => splitReferenceList(ego.synIDS));
            const ownIdentityId = slot.identity.imgUrl.toLowerCase();
            const hasEgoSynergy = egos.some(ego => (
                identityReferences.includes(ego.imgUrl.toLowerCase())
                || splitReferenceList(ego.synIDS).includes(ownIdentityId)
            ));

            const member: MemberSynergy = {
                index,
                name: getMemberName(slot.identity),
                sinner: getSinnerLabel(slot.identity.sinner),
                imgUrl: slot.identity.imgUrl,
                keywords: identityKeywords,
                egoKeywords: sortKeywords(egos.flatMap(getEgoKeywords)),
                recommendedIds: Array.from(new Set([...identityReferences, ...egoReferences]
                    .filter(reference => reference.startsWith("id_") && reference !== ownIdentityId))),
                hasEgoSynergy,
                supportPassives: getPassiveInfo(slot.identity, lang),
            };

            if (isSupport) result.supportMembers.push(member);
            else result.combatMembers.push(member);
            return result;
        }, { combatMembers: [], supportMembers: [] });
    }, [slots, lang]);

    const pairs = useMemo<PairSynergy[]>(() => {
        const result: PairSynergy[] = [];
        for (let i = 0; i < combatMembers.length; i++) {
            for (let j = i + 1; j < combatMembers.length; j++) {
                const a = combatMembers[i];
                const b = combatMembers[j];
                const keywords = sortKeywords(a.keywords.filter(keyword => b.keywords.includes(keyword)));
                const egoKeywords = sortKeywords([
                    ...a.egoKeywords.filter(keyword => b.keywords.includes(keyword)),
                    ...b.egoKeywords.filter(keyword => a.keywords.includes(keyword)),
                ]);
                const recommended = a.recommendedIds.includes(b.imgUrl.toLowerCase())
                    || b.recommendedIds.includes(a.imgUrl.toLowerCase());
                if (keywords.length || egoKeywords.length || recommended) result.push({ a, b, keywords, egoKeywords, recommended });
            }
        }
        return result.sort((a, b) => (
            Number(b.recommended) - Number(a.recommended)
            || b.keywords.length - a.keywords.length
            || b.egoKeywords.length - a.egoKeywords.length
        ));
    }, [combatMembers]);

    const nodes = useMemo<MapNode[]>(() => {
        return combatMembers.map((member, index) => {
            const position = getNodePosition(index, combatMembers.length);
            const score = pairs
                .filter(pair => pair.a.index === member.index || pair.b.index === member.index)
                .length;
            return { ...member, ...position, score };
        });
    }, [combatMembers, pairs]);

    const primaryKeyword = MAIN_KEYWORDS
        .map(keyword => ({ keyword, count: combatMembers.filter(member => member.keywords.includes(keyword)).length }))
        .sort((a, b) => b.count - a.count)[0];
    const hoveredTooltip = hoveredPair ? getPairTooltip(hoveredPair, lang, statuses) : "";

    return (
        <section className="tb-synergy">
            <CollapsibleSection storageKey="synergy-map" title={t("TbSynergy.map")} className="tb-synergy-card tb-synergy-card--map" collapsible={canToggle} hideHeading={!canToggle}>
                <div className="tb-synergy-card-header">
                    <h2 className="tb-synergy-title-tooltip">
                        {t("TbSynergy.map")}
                        <span className="tb-synergy-title-tooltip-content">{t("TbSynergy.mapTooltip")}</span>
                    </h2>
                    <span>{combatMembers.length}/12</span>
                </div>
                <div className="tb-synergy-map-shell">
                    {!!supportMembers.length && (
                        <div className="tb-synergy-support-wall">
                            {supportMembers.map(member => (
                                <div className="tb-synergy-support" key={member.index} title={member.name}>
                                    <img src={`${process.env.PUBLIC_URL}/images/identities/${member.imgUrl}.1.webp`} onError={event => handleIdentityImageError(event, member.imgUrl)} alt={member.name} />
                                    <span>{member.sinner}</span>
                                    <div className="tb-synergy-support-costs">
                                        {member.supportPassives.slice(0, 2).flatMap(passive => passive.sins.map((sin, index) => (
                                            <b key={`${member.index}-${sin}-${index}`}>
                                                <img src={`${process.env.PUBLIC_URL}/images/sins/${normalizeTbSin(sin)}.webp`} alt={sin} />
                                                {passive.counts[index] || passive.counts[0] || ""}
                                            </b>
                                        )))}
                                    </div>
                                    {member.supportPassives[0] && (
                                        <em className="tb-synergy-support-condition">
                                            {t(getPassiveConditionKey(member.supportPassives[0].condition))}
                                        </em>
                                    )}
                                </div>
                            ))}
                        </div>
                    )}
                    {combatMembers.length < 2 ? (
                        <p className="tb-synergy-empty">{t("TbSynergy.needMembers")}</p>
                    ) : (
                        <div className="tb-synergy-map" style={{ width: MAP_SIZE, height: MAP_SIZE }}>
                            <svg className="tb-synergy-map-lines" viewBox={`0 0 ${MAP_SIZE} ${MAP_SIZE}`}>
                                {pairs.map(pair => {
                                    const a = nodes.find(node => node.index === pair.a.index);
                                    const b = nodes.find(node => node.index === pair.b.index);
                                    if (!a || !b) return null;
                                    const isMemberLinkActive = hoveredMemberIndex !== null && (pair.a.index === hoveredMemberIndex || pair.b.index === hoveredMemberIndex);
                                    return (
                                        <g
                                            key={`${a.index}-${b.index}`}
                                            onMouseEnter={() => setHoveredPair(pair)}
                                            onMouseLeave={() => setHoveredPair(null)}
                                        >
                                            <line
                                                x1={a.x}
                                                y1={a.y}
                                                x2={b.x}
                                                y2={b.y}
                                                className={[
                                                    "tb-synergy-link",
                                                    pair.recommended ? "tb-synergy-link--direct" : "",
                                                    !pair.recommended && !pair.keywords.length && pair.egoKeywords.length ? "tb-synergy-link--ego" : "",
                                                    isMemberLinkActive ? "tb-synergy-link--member-active" : "",
                                                ].join(" ")}
                                            />
                                            <line
                                                x1={a.x}
                                                y1={a.y}
                                                x2={b.x}
                                                y2={b.y}
                                                className="tb-synergy-link-hitbox"
                                            />
                                        </g>
                                    );
                                })}
                            </svg>
                            <div className="tb-synergy-map-total">
                                <b>{combatMembers.length}</b>
                                <small>/12</small>
                                {primaryKeyword?.count > 0 && <span>{getKeywordLabel(primaryKeyword.keyword, lang, statuses)}</span>}
                            </div>
                            {hoveredPair && (
                                <div className="tb-synergy-line-tooltip">
                                    {hoveredPair.a.sinner} - {hoveredPair.b.sinner}: {hoveredTooltip}
                                </div>
                            )}
                            {nodes.map(node => (
                                <div
                                    className={`tb-synergy-node ${node.hasEgoSynergy ? "tb-synergy-node--ego-match" : ""}`}
                                    key={node.index}
                                    style={{ left: node.x, top: node.y }}
                                    onMouseEnter={() => setHoveredMemberIndex(node.index)}
                                    onMouseLeave={() => setHoveredMemberIndex(null)}
                                >
                                    <img src={`${process.env.PUBLIC_URL}/images/identities/${node.imgUrl}.1.webp`} onError={event => handleIdentityImageError(event, node.imgUrl)} alt={node.name} />
                                    <b>{node.score}</b>
                                    {node.hasEgoSynergy && <i className="tb-synergy-node-ego-mark" title={lang === "ru" ? "Синергия с E.G.O" : "E.G.O synergy"} aria-label={lang === "ru" ? "Синергия с E.G.O" : "E.G.O synergy"}>E</i>}
                                    <span>{node.sinner}</span>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </CollapsibleSection>

            <CollapsibleSection storageKey="synergy-damage" title={t("TbDamage.header", "Damage")} className="tb-synergy-card tb-synergy-card--damage" collapsible={canToggle} hideHeading={!canToggle}>
                <TbDamage/>
            </CollapsibleSection>
        </section>
    );
};
