import React, { useState } from "react";
import { useTranslation } from "react-i18next";
import { useQueryClient } from "react-query";
import { useTypedSelector } from "../../../hooks/useTypedSelector";
import { SINNER_ORDER } from "../../../store/reducers/tb-reducer";
import { supabase } from "../../../tools/supabaseClient";
import { encodeFormationCode } from "../tb-slots/tb-utils";
import { StatusAutocomplete } from "./StatusAutocomplete";
import { BattleOrderSelector } from "./BattleOrderSelector";
import { getTeamGiftIds, TeamGiftSelector } from "./TeamGiftSelector";
import { TeamStatusOption } from "./status-utils";
import { TEAM_CONTENT_TYPES, TEAM_STATUS_COLORS, TeamContentType, TeamPreset, applyBattleOrder } from "./team-types";

type Props = {
  team: TeamPreset;
  statusOptions: TeamStatusOption[];
  onClose: () => void;
  onSaved: () => void;
};

const parseStatuses = (value: unknown): string[] => {
  if (Array.isArray(value)) return value.filter((item): item is string => typeof item === "string");
  if (typeof value !== "string") return [];
  try { return parseStatuses(JSON.parse(value)); } catch { return []; }
};

export const TeamEditForm: React.FC<Props> = ({ team, statusOptions, onClose, onSaved }) => {
  const { i18n } = useTranslation();
  const ru = i18n.language === "ru";
  const { slots } = useTypedSelector(store => store.tbReducer);
  const queryClient = useQueryClient();
  const [titleRu, setTitleRu] = useState(team.title_ru || team.title || "");
  const [titleEn, setTitleEn] = useState(team.title_en || team.title || "");
  const [descriptionRu, setDescriptionRu] = useState(team.description_ru || team.description || "");
  const [descriptionEn, setDescriptionEn] = useState(team.description_en || team.description || "");
  const [youtubeUrl, setYoutubeUrl] = useState(team.youtube_url || "");
  const [isPublic, setIsPublic] = useState(team.is_public !== false && team.moderation_status !== "private");
  const [contentType, setContentType] = useState<TeamContentType>(team.content_type || "mirror_dungeon");
  const [statuses, setStatuses] = useState(() => parseStatuses(team.statuses));
  const [mainStatus, setMainStatus] = useState(team.main_status || "");
  const [backgroundStatus, setBackgroundStatus] = useState(team.background_status || "");
  const [selectedGifts, setSelectedGifts] = useState(() => getTeamGiftIds(team.recommended_gifts));
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");
  const [replaceLineup, setReplaceLineup] = useState(false);
  const [battleOrders, setBattleOrders] = useState<Record<number, number>>(() => Object.fromEntries((team.lineup || []).map((slot, index) => [index, Number(slot.battle_order)]).filter(([, value]) => value > 0)));
  const currentMembers = slots.filter(slot => slot.identity).length;

  const changeStatuses = (next: string[]) => {
    setStatuses(next);
    if (!next.includes(mainStatus)) setMainStatus(next[0] || "");
    if (!next.includes(backgroundStatus)) setBackgroundStatus("");
  };

  const submit = async (event: React.FormEvent) => {
    event.preventDefault();
    setSaving(true);
    setError("");
    try {
      if (!(titleRu.trim() || titleEn.trim())) throw new Error(ru ? "Заполните название хотя бы на одном языке." : "Add a title in at least one language.");
      const savedCombatCount = (team.lineup || []).filter(slot => slot.identity && slot.role !== "support").length;
      if (isPublic && !replaceLineup && savedCombatCount > 7) throw new Error(ru ? "В публичной команде может быть не более 7 бойцов на поле." : "A public team may have no more than 7 units on the field.");
      const update: Record<string, unknown> = {
        title: titleRu.trim() || titleEn.trim(),
        title_ru: titleRu.trim() || null,
        title_en: titleEn.trim() || null,
        description: descriptionRu.trim() ? descriptionRu : descriptionEn,
        description_ru: descriptionRu.trim() ? descriptionRu : null,
        description_en: descriptionEn.trim() ? descriptionEn : null,
        is_public: isPublic,
        content_type: contentType,
        moderation_status: isPublic ? "pending" : "private",
        youtube_url: youtubeUrl.trim() || null,
        statuses,
        main_status: mainStatus || null,
        background_status: backgroundStatus || null,
        recommended_gifts: contentType === "mirror_dungeon" ? selectedGifts : []
      };
      if (replaceLineup) {
        if (!currentMembers) throw new Error(ru ? "Текущий состав пуст." : "The current team is empty.");
        const combatCount = slots.filter(slot => slot.identity && slot.role !== "support").length;
        if (isPublic && combatCount > 7) throw new Error(ru ? "В публичной команде может быть не более 7 бойцов на поле." : "A public team may have no more than 7 units on the field.");
        const orderedSlots = applyBattleOrder(slots, battleOrders);
        const lineup = orderedSlots.map((slot, index) => ({
          sinner: SINNER_ORDER[index],
          role: slot.role === "support" ? "support" : "combat",
          battle_order: slot.role === "support" ? (battleOrders[index] || null) : slot.teamCodeSlotType,
          identity: slot.identity ? {
            imgUrl: slot.identity.imgUrl,
            nameRU: (slot.identity as any).nameRU || (slot.identity as any).nameRu,
            nameEN: (slot.identity as any).nameEN || (slot.identity as any).nameEn
          } : null,
          ego: Object.fromEntries(Object.entries(slot.ego || {}).filter(([, ego]) => ego).map(([rarity, ego]: [string, any]) => [rarity, ego.imgUrl]))
        }));
        update.team_code = await encodeFormationCode(orderedSlots, queryClient);
        update.lineup = lineup;
        update.slot_roles = lineup.map(slot => slot.role);
      }
      const { error: updateError } = await supabase.from("team_presets").update(update).eq("id", team.id);
      if (updateError) throw updateError;
      onSaved();
    } catch (updateError: any) {
      setError(updateError?.message || (ru ? "Не удалось обновить команду." : "Could not update the team."));
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="team-edit-overlay" role="dialog" aria-modal="true" aria-label={ru ? "Редактирование команды" : "Edit team"} onMouseDown={event => event.target === event.currentTarget && onClose()}>
      <form className="team-edit-form" onSubmit={submit}>
        <header><div><small className="community-kicker">EDIT TEAM</small><h2>{ru ? "Редактировать команду" : "Edit team"}</h2></div><button type="button" className="team-edit-close" onClick={onClose} aria-label={ru ? "Закрыть" : "Close"}>×</button></header>
        <div className="team-edit-localized"><label><span>Название RU</span><input value={titleRu} onChange={event => setTitleRu(event.target.value)} maxLength={120} /></label><label><span>Title EN</span><input value={titleEn} onChange={event => setTitleEn(event.target.value)} maxLength={120} /></label></div>
        <div className="team-edit-localized"><label><span>Описание RU</span><textarea value={descriptionRu} onChange={event => setDescriptionRu(event.target.value)} maxLength={5000} rows={4} /></label><label><span>Description EN</span><textarea value={descriptionEn} onChange={event => setDescriptionEn(event.target.value)} maxLength={5000} rows={4} /></label></div>
        <div className="team-edit-localized"><label><span>{ru ? "Тип контента" : "Content type"}</span><select value={contentType} onChange={event => setContentType(event.target.value as TeamContentType)}>{TEAM_CONTENT_TYPES.map(option => <option value={option.value} key={option.value}>{ru ? option.ru : option.en}</option>)}</select></label><label><span>{ru ? "Доступ" : "Visibility"}</span><select value={isPublic ? "public" : "private"} onChange={event => setIsPublic(event.target.value === "public")}><option value="public">{ru ? "Публичная" : "Public"}</option><option value="private">{ru ? "Приватная" : "Private"}</option></select></label></div>
        <div className="team-edit-lineup">
          <div><strong>{ru ? "Состав команды" : "Team lineup"}</strong><small>{ru ? `Сейчас в билдере: ${currentMembers}/12` : `Currently in builder: ${currentMembers}/12`}</small></div>
          <button type="button" className={replaceLineup ? "is-active" : ""} disabled={!currentMembers} onClick={() => setReplaceLineup(value => !value)}>{replaceLineup ? (ru ? "Текущий состав выбран" : "Current lineup selected") : (ru ? "Заменить текущим составом" : "Replace with current lineup")}</button>
        </div>
        {contentType === "mirror_dungeon" && <TeamGiftSelector selected={selectedGifts} onChange={setSelectedGifts} ru={ru} />}
        {replaceLineup && <BattleOrderSelector slots={slots} orders={battleOrders} onChange={setBattleOrders} ru={ru} />}
        <div className="team-status-field">
          <span>{ru ? "Теги" : "Tags"}</span>
          <StatusAutocomplete options={statusOptions} selected={statuses} onChange={changeStatuses} placeholder={ru ? "Начните писать название тега…" : "Start typing a tag…"} mainStatus={mainStatus} onMainChange={setMainStatus} noResults={ru ? "Подходящих тегов нет" : "No matching tags"} mainTitle={ru ? "Сделать основным" : "Set as main"} />
          <div className="team-card-accent-field">
            <span>{ru ? "Фоновый акцент" : "Background accent"}</span>
            <button type="button" className={!backgroundStatus ? "is-active" : ""} onClick={() => setBackgroundStatus("")}>{ru ? "Без цвета" : "No color"}</button>
            {statuses.filter(status => TEAM_STATUS_COLORS[status]).map(status => <button type="button" className={backgroundStatus === status ? "is-active" : ""} style={{ "--status-choice-rgb": TEAM_STATUS_COLORS[status] } as React.CSSProperties} onClick={() => setBackgroundStatus(status)} key={status}><i />{statusOptions.find(option => option.value === status)?.label || status}</button>)}
          </div>
        </div>
        <label><span>{ru ? "YouTube-ссылка" : "YouTube link"}</span><input type="url" value={youtubeUrl} onChange={event => setYoutubeUrl(event.target.value)} placeholder="https://youtu.be/…" /></label>
        {error && <div className="community-error">{error}</div>}
        <footer><small>{isPublic ? (ru ? "После изменения команда снова отправится на модерацию." : "Editing sends the team back to moderation.") : (ru ? "Приватная команда не проходит модерацию." : "Private teams are not moderated.")}</small><div><button type="button" className="team-edit-cancel" onClick={onClose}>{ru ? "Отмена" : "Cancel"}</button><button type="submit" className="community-load-button" disabled={saving}>{saving ? (ru ? "Сохранение…" : "Saving…") : (ru ? "Сохранить" : "Save")}</button></div></footer>
      </form>
    </div>
  );
};
