import React, { useMemo } from 'react';
import { useTranslation } from "react-i18next";
import { LanguageDisclaimer } from "../language-disclaimer/LanguageDisclaimer";
import { EntitySection } from "./entity-section/EntitySection";
import { EventsSection } from "./events-section/EventsSection";
import { NavigationSection } from "./navigation-section/NavigationSection";
import { OfficialLinksSection } from "./official-links-section/OfficialLinksSection";
import { ToDoSection } from "./todo-section/ToDoSection";

import { useFetchNewsList } from "../../api/useFetchByKeys";
import { NewsInterface } from "../../store/reducers/news_list-reducers";

import { BoostySVG } from "../svg/BoostySVG";
import { DiscordIconSVG } from "../svg/DiscordIcon";
import { XIconSVG } from "../svg/XIcon";
import { HeaderAuthButtons } from "./HeaderAuthButtons";

import "./MainInfo.css";

const CHIBI_IMAGES = [
    "/images/chibi/dante.png", "/images/chibi/don.png", "/images/chibi/faust.png",
    "/images/chibi/gregor.png", "/images/chibi/heath.png", "/images/chibi/holo.png",
    "/images/chibi/merso.png", "/images/chibi/otus.png", "/images/chibi/rodi.png",
    "/images/chibi/rous.png", "/images/chibi/sinkisng.png", "/images/chibi/sisma.png",
    "/images/chibi/zlo.png"
];

const getRandomChibis = (count: number) => {
    const shuffled = [...CHIBI_IMAGES];
    for (let i = shuffled.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
    }
    return shuffled.slice(0, count);
};

export const MainInfo: React.FC = () => {
    const { t, i18n } = useTranslation();
    const { data: newsFromApi, isLoading } = useFetchNewsList();
    const currentLang = i18n.language === 'ru' ? 'ru' : 'en';

    const uniqueChibis = useMemo(() => getRandomChibis(3), []);

    const openLink = (url: string) => {
        if (url.startsWith('http')) {
            window.open(url, '_blank', 'noopener,noreferrer');
        }
    };

    return (
        <section className="main-info">
            <header className="main-info-header-main">
                <HeaderAuthButtons />
                <h1>
                    Great <span>Limbus</span> Library
                </h1>
                <p className="main-info-header-description">
                    {t(`MainInfo.headerDescription1`)}
                </p>
                <LanguageDisclaimer />
            </header>

            <div className="vibe-section animate-fade-in">
                <div className="vibe-news-grid">
                    {!isLoading && newsFromApi && newsFromApi.slice(0, 3).map((item: NewsInterface, i: number) => {
                        const displayTitle = currentLang === 'ru' ? item.title : item.enTitle;
                        const displayDesc = currentLang === 'ru' ? item.desc : item.enDesc;

                        // --------------------------------------------------------------
                        // ★ Новая логика: определяем, является ли linkPath внешней ссылкой
                        // --------------------------------------------------------------
                        const isExternal = item.linkPath?.startsWith('http://') || item.linkPath?.startsWith('https://');
                        const targetUrl = isExternal
                            ? item.linkPath  // внешняя – используем как есть
                            : `https://gll-fun.com/limbus/${currentLang}/${item.linkPath}`; // внутренняя

                        return (
                            <div 
                                key={i} 
                                className="vibe-banner-slot" 
                                onClick={() => openLink(targetUrl)}
                                style={{ cursor: 'pointer' }}
                            >
                                <div className="vibe-banner-content">
                                    <div className="vibe-banner-text">
                                        <h3 className="vibe-banner-title">
                                            {displayTitle}
                                            {isExternal && (
                                                <span className="external-link-icon" style={{ marginLeft: '6px', fontSize: '0.8em' }}>
                                                    ↗
                                                </span>
                                            )}
                                        </h3>
                                        <p className="vibe-banner-desc">{displayDesc}</p>
                                    </div>
                                    <img src={uniqueChibis[i]} alt="Chibi" className="vibe-banner-chibi" />
                                </div>
                                <div className="vibe-banner-border-corner" />
                            </div>
                        );
                    })}
                </div>

                <aside className="vibe-social-sidebar">
                    <button className="vibe-social-btn discord" onClick={() => openLink("https://discord.gg/BGpmmqknWE")} aria-label="Discord">
                        <div className="vibe-btn-accent-line" />
                        <div className="vibe-btn-content">
                            <div className="vibe-btn-icon"><DiscordIconSVG /></div>
                            <div className="vibe-btn-separator" />
                            <span>Discord</span>
                        </div>
                    </button>

                    <button className="vibe-social-btn x" onClick={() => openLink("https://x.com/GLLimbus")} aria-label="GLL on X">
                        <div className="vibe-btn-accent-line" />
                        <div className="vibe-btn-content">
                            <div className="vibe-btn-icon"><XIconSVG /></div>
                            <div className="vibe-btn-separator" />
                            <span>X</span>
                        </div>
                    </button>

                    <button className="vibe-social-btn boosty" onClick={() => openLink("https://boosty.to/gll-fun")}>
                        <div className="vibe-btn-accent-line" />
                        <div className="vibe-btn-content">
                            <div className="vibe-btn-icon"><BoostySVG /></div>
                            <div className="vibe-btn-separator" />
                            <span>Boosty</span>
                        </div>
                    </button>
                </aside>
            </div>

            <section className="main-info-content-grid">
                <div className="main-info-column-left">
                    <EntitySection />
                    <NavigationSection />
                    <ToDoSection />
                    <OfficialLinksSection />
                </div>
                <aside className="main-info-column-right">
                    <EventsSection />
                </aside>
            </section>
        </section>
    );
};