import { Session } from "@supabase/supabase-js";
import { useEffect, useState } from "react";
import { supabase } from "../tools/supabaseClient";
import { DiscordAccess, verifyDiscordAccess } from "../tools/discordAccess";

export const DISCORD_GUILD_ID = "1229849684302889063";
export const DISCORD_REVIEWER_ROLE_IDS = new Set([
  "1356325679150661712",
  "1356316522402021487",
  "1302564393887993929",
  "1229849777261248553",
  "1304083538831867924",
  "1229850737631166576",
  "1302579987442044930"
]);

let cachedUserId = "";
let cachedAccess: DiscordAccess = { admin: false, reviewer: false };
let cachedAt = 0;
let pendingCheck: { userId: string; promise: Promise<DiscordAccess> } | null = null;

const verifyReviewerAccess = async (session: Session | null) => {
  const userId = session?.user?.id || "";
  if (!userId) return { admin: false, reviewer: false };
  const cacheTtl = cachedAccess.admin || cachedAccess.reviewer ? 5 * 60 * 1000 : 5 * 1000;
  if (userId === cachedUserId && Date.now() - cachedAt < cacheTtl) return cachedAccess;
  if (pendingCheck?.userId === userId) return pendingCheck.promise;

  const promise = verifyDiscordAccess(session).catch(() => ({ admin: false, reviewer: false })).then(access => {
    cachedUserId = userId;
    cachedAccess = access;
    cachedAt = Date.now();
    return access;
  }).finally(() => {
    if (pendingCheck?.promise === promise) pendingCheck = null;
  });
  pendingCheck = { userId, promise };

  return promise;
};

export const useReviewerAccess = () => {
  const [isReviewer, setIsReviewer] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [reconnectRequired, setReconnectRequired] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let mounted = true;
    const applySession = async (session: Session | null) => {
      const access = await verifyReviewerAccess(session);
      if (!mounted) return;
      setIsReviewer(access.reviewer);
      setIsAdmin(access.admin);
      setReconnectRequired(access.reconnectRequired === true);
      setLoading(false);
    };

    supabase.auth.getSession().then(({ data }) => applySession(data.session));
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      window.setTimeout(() => applySession(session), 0);
    });

    return () => {
      mounted = false;
      subscription.unsubscribe();
    };
  }, []);

  return { isReviewer, isAdmin, reconnectRequired, loading };
};
