import React, { useEffect, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { useQueryClient } from 'react-query';
import { Filters } from '../../filters/Filters';
import { useTypedSelector } from '../../../hooks/useTypedSelector';
import { createGiftList } from '../formatted-text-gift/MDGiftFormattedText';
import { MDEvent } from '../../../store/reducers/md-event-interface'; 
import { MDEventOption } from '../events/option/MDEventOption'; 
import './FloorThemes.css';

interface MDTheme {
    id: string; 
    name: string; 
    complexity: string; 
    events: string; 
    possiblebosses: string; 
    uniquegifts: string; 
    tip: string; 
    description: string; // Добавили новое поле описания в локальный интерфейс
}

export const FloorThemes: React.FC = () => {
    const themes = useQueryClient().getQueryData<MDTheme[]>("themes") || null;
    const allEvents = useQueryClient().getQueryData<MDEvent[]>("md-events") || null;
    const { t, i18n } = useTranslation();
    const { value: searchValue } = useTypedSelector(store => store.searchReducer);
    
    // Достаем состояние обновленного редюсера фильтров
    const filterState = useTypedSelector(store => store.filterReducer);
    const selectedFloors = filterState.types.complexityFloor;
    const { normal: filterNormal, hard: filterHard } = filterState.types.complexityMode;
    const selectedTips = filterState.types.mdThemeTips; // Наш новый стейт для буквенных тегов

    const [activeThemeId, setActiveThemeId] = useState<string | null>(null);
    const [rowShiftThemeId, setRowShiftThemeId] = useState<string | null>(null);
    const [selectedEvent, setSelectedEvent] = useState<MDEvent | null>(null);

    useEffect(() => {
        if (!activeThemeId) return;
        const closeOnOutsidePointer = (event: PointerEvent) => {
            const target = event.target as Element | null;
            if (target?.closest('.MDThemes-info-content') || target?.closest('.MDThemes-poster-wrapper')) return;
            setActiveThemeId(null);
            setRowShiftThemeId(null);
        };
        document.addEventListener('pointerdown', closeOnOutsidePointer);
        return () => document.removeEventListener('pointerdown', closeOnOutsidePointer);
    }, [activeThemeId]);

    const toggleTheme = (themeId: string, section: HTMLElement) => {
        if (activeThemeId === themeId) {
            setActiveThemeId(null);
            setRowShiftThemeId(null);
            return;
        }

        const info = section.querySelector<HTMLElement>('.MDThemes-info-content');
        const wouldOverflow = info
            ? section.getBoundingClientRect().right + info.getBoundingClientRect().width > document.documentElement.clientWidth
            : false;

        setRowShiftThemeId(wouldOverflow ? themeId : null);
        setActiveThemeId(themeId);
    };

    const getLocalizedValue = (fieldValue: string): string => {
        if (!fieldValue) return '';
        const parts = fieldValue.split('|');
        return parts.length === 2 
            ? (i18n.language === 'ru' ? parts[0].trim() : parts[1].trim())
            : fieldValue;
    };

    // --- Обновленная комплексная логика фильтрации темы с поддержкой диапазонов ---
    const checkComplexityFilter = (theme: MDTheme): boolean => {
        if (!theme.complexity) return false;

        // Вспомогательная функция для парсинга "3", "1-3" или "1-10" в массив конкретных этажей
        const parseFloorString = (str: string): number[] => {
            if (!str) return [];
            // Если это диапазон (например, "1-10")
            if (str.includes('-')) {
                const [start, end] = str.split('-').map(num => parseInt(num, 10));
                if (!isNaN(start) && !isNaN(end)) {
                    const floors: number[] = [];
                    for (let i = start; i <= end; i++) {
                        floors.push(i);
                    }
                    return floors;
                }
            }
            // Если это просто одиночное число (например, "3")
            const singleFloor = parseInt(str, 10);
            return !isNaN(singleFloor) ? [singleFloor] : [];
        };

        // 1. Парсим обе части: "1-10 | 1-3" -> массив этажей для Normal и Hard
        const parts = theme.complexity.split('|').map(p => p.trim());
        const normalFloors = parseFloorString(parts[0]);
        const hardFloors = parseFloorString(parts[1] || parts[0]); // Если hard не указан, берем normal

        // Собираем общий пул этажей темы в зависимости от выбранных модов (N / H)
        const targetFloors: number[] = [];
        
        if (filterNormal && !filterHard) {
            targetFloors.push(...normalFloors);
        } else if (!filterNormal && filterHard) {
            targetFloors.push(...hardFloors);
        } else {
            // Если оба фильтра модов включены или оба выключены — проверяем все этажи темы
            targetFloors.push(...normalFloors, ...hardFloors);
        }

        // Убираем дубликаты этажей для оптимизации
        const uniqueTargetFloors = Array.from(new Set(targetFloors));

        if (uniqueTargetFloors.length === 0) return false;

        // 2. Валидация кнопок этажей 1-5F
        const activeFloorFilters = Object.keys(selectedFloors)
            .filter(f => selectedFloors[f])
            .map(f => parseInt(f.replace("F", ""), 10));

        if (activeFloorFilters.length > 0) {
            // Тема проходит, если хотя бы один из её этажей совпадает с нажатой кнопкой 1-5F
            const hasMatchingFloor = uniqueTargetFloors.some(f => activeFloorFilters.includes(f));
            if (!hasMatchingFloor) return false;
        }

        // 3. Валидация буквенных тегов из поля tip (E, IM, C, IN, W, RR, AT, SIN, ST, SP)
        const activeTipFilters = Object.keys(selectedTips).filter(tag => selectedTips[tag]);

        if (activeTipFilters.length > 0) {
            const themeTips = theme.tip ? theme.tip.split(',').map(t => t.trim()) : [];

            // Тема должна удовлетворять КАЖДОМУ выбранному буквенному фильтру (логика AND)
            const matchesAllTips = activeTipFilters.every(filterTag => {
                if (filterTag === "IM") {
                    // Авто-диапазон Intermezzo: хотя бы один этаж темы находится в пределах от 5 до 10 включительно
                    return uniqueTargetFloors.some(f => f >= 5 && f <= 10);
                }
                if (filterTag === "E") {
                    // Авто-диапазон End: хотя бы один этаж темы строго больше 10
                    return uniqueTargetFloors.some(f => f > 10);
                }
                // Для остальных тегов (C, IN, W...) ищем прямое вхождение в поле tip темы
                return themeTips.includes(filterTag);
            });

            if (!matchesAllTips) return false;
        }

        return true;
    };

    const handleEventClick = (e: React.MouseEvent, eventId: string) => {
        e.stopPropagation(); 
        if (allEvents) {
            const foundEvent = allEvents.find(ev => ev.id === eventId);
            if (foundEvent) setSelectedEvent(foundEvent);
        }
    };

    const renderComplexity = (complexityStr: string) => {
        if (!complexityStr) return null;
        const [normal, hard] = complexityStr.split('|').map(s => s.trim());
        const isRu = i18n.language === 'ru';

        const formatFloor = (str: string) => {
            if (!str) return '';
            return str.replace(/\d+/g, (match) => `${match}F`);
        };

        return (
            <div className="MDThemes-complexity">
                {normal && (
                    <div>
                        <strong>{isRu ? 'Нормальный' : 'Normal'}:</strong> {formatFloor(normal)}
                    </div>
                )}
                {hard && (
                    <div>
                        <strong>{isRu ? 'Сложный' : 'Hard'}:</strong> {formatFloor(hard)}
                    </div>
                )}
            </div>
        );
    };

    // Функция для рендеринга нового поля описания с поддержкой <br>
    const renderDescription = (descriptionStr: string) => {
        if (!descriptionStr) return null;
        const localizedDescription = getLocalizedValue(descriptionStr);

        return (
            <div className="MDThemes-description">
                {localizedDescription.split('<br>').map((line, index, array) => (
                    <React.Fragment key={index}>
                        {line}
                        {index < array.length - 1 && <br />}
                    </React.Fragment>
                ))}
            </div>
        );
    };

    const renderEvents = (eventsStr: string) => {
        if (!eventsStr) return null;
        const events = eventsStr.split(',').map(e => e.trim());
        return (
            <div className="MDThemes-events-icons">
                {events.map(eventId => (
                    <img 
                        key={eventId}
                        src={`${process.env.PUBLIC_URL}/images/md-events/${eventId}.webp`} 
                        alt={eventId}
                        className="MDThemes-mini-item clickable-item"
                        title={eventId}
                        onClick={(e) => handleEventClick(e, eventId)}
                    />
                ))}
            </div>
        );
    };

    const renderBosses = (bossesStr: string) => {
        if (!bossesStr) return null;
        const bossesArray = Array.from(
            bossesStr.matchAll(/([^,[]+)\[([^|]+)\|([^\]]+)\](?:,|$)/g)
        );
        
        return (
            <div className="MDThemes-bosses-block">
                <h4>{t("MDEventOption.bosses")}:</h4>
                <div className="MDThemes-bosses-wrapper">
                    {bossesArray.map((match, index) => {
                        const [, imgId, nameRU, nameEN] = match.map(s => s.trim());
                        const bossName = i18n.language === 'ru' ? nameRU : nameEN;

                        return (
                            <div className="MDThemes-boss-card" key={`${imgId}-${index}`}>
                                <img
                                    className="MDThemes-mini-item"
                                    src={`${process.env.PUBLIC_URL}/images/enemies/${imgId}.webp`}
                                    alt={`enemy ${bossName}`} 
                                    onError={(e) => {
                                        (e.target as HTMLImageElement).src = `${process.env.PUBLIC_URL}/images/general/unknown.webp`;
                                    }}
                                />
                                <span className="MDThemes-boss-name">{bossName}</span>
                            </div>
                        );
                    })}
                </div>
            </div>
        );
    };

    // Основная фильтрация данных
    const filteredData = (() => {
        if (!themes) return [];
        const searchLower = searchValue.toLowerCase();

        return themes
            .filter(theme => getLocalizedValue(theme.name).toLowerCase().includes(searchLower))
            .filter(theme => checkComplexityFilter(theme))
            .sort((a, b) => {
                const numA = parseInt(a.id.replace(/\D/g, ''), 10) || 0;
                const numB = parseInt(b.id.replace(/\D/g, ''), 10) || 0;
                return numA - numB;
            });
    })();

    return (
        <>
            <Filters pageType="themes" />
            <div className="MDThemes" onClick={(event) => {
                if (event.target === event.currentTarget) {
                    setActiveThemeId(null);
                    setRowShiftThemeId(null);
                }
            }}>
                {filteredData.length > 0 && (
                    <div className="MDThemes-container" onClick={(event) => {
                        if (event.target === event.currentTarget) {
                            setActiveThemeId(null);
                            setRowShiftThemeId(null);
                        }
                    }}>
                        {filteredData.map(theme => {
                            const isExpanded = activeThemeId === theme.id;
                            const themeName = getLocalizedValue(theme.name);

                            return (
                                <section
                                    key={theme.id}
                                    className={`MDThemes-section ${isExpanded ? 'is-active' : ''} ${rowShiftThemeId === theme.id ? 'needs-row-shift' : ''}`}
                                    onClick={(event) => toggleTheme(theme.id, event.currentTarget)}
                                >
                                    <div className="MDThemes-poster-wrapper">
                                        <div className="MDThemes-hook" />
                                        <img
                                            src={`${process.env.PUBLIC_URL}/images/md-themes/${theme.id}.webp`}
                                            alt={themeName}
                                            className="MDThemes-poster"
                                            loading="lazy"
                                            onError={(e) => {
                                                (e.target as HTMLImageElement).src = `${process.env.PUBLIC_URL}/images/general/unknown.webp`;
                                            }}
                                        />
                                    </div>

                                    <div className="MDThemes-info-content" onClick={(e) => e.stopPropagation()}>
                                        <h3 className="MDThemes-info-title">{themeName}</h3>
                                        
                                        {renderComplexity(theme.complexity)}

                                        {/* Вставка описания сразу после complexity */}
                                        {renderDescription(theme.description)}
                                        
                                        {theme.uniquegifts && (
                                            <div className="MDThemes-gifts-block">
                                                <h4>{t("MDEventOption.gifts_uniquegifts")}:</h4>
                                                <div className="MDEvents-ego-gifts-section clickable-gifts">
                                                    {createGiftList(theme.uniquegifts.split(',').map(id => id.trim()), t)}
                                                </div>
                                            </div>
                                        )}

                                        {renderBosses(theme.possiblebosses)}
                                        
                                        {theme.events && (
                                            <div className="MDThemes-events-block">
                                                <h4>{t("MDEventOption.events")}:</h4>
                                                {renderEvents(theme.events)}
                                            </div>
                                        )}
                                    </div>
                                </section>
                            );
                        })}
                    </div>
                )}

                {selectedEvent && (
                    <div className="MDEvents-modal-overlay" onClick={() => setSelectedEvent(null)}>
                        <div className="MDEvents-modal-content" onClick={(e) => e.stopPropagation()}>
                            <button className="MDEvents-modal-close" onClick={() => setSelectedEvent(null)}>×</button>
                            <div className="MDEvents-modal-header">
                                <h3>{i18n.language === "ru" ? selectedEvent.abnoRU : selectedEvent.abnoEN}</h3>
                            </div>
                            <div className="MDEvents-modal-body">
                                 <MDEventOption option={i18n.language === "ru" ? selectedEvent.choiceRU : selectedEvent.choiceEN} />
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </>
    );
};
