import { Session, User } from "@supabase/supabase-js";
import { useEffect, useState } from "react";
import { supabase } from "../tools/supabaseClient";
import { verifyDiscordAccess } from "../tools/discordAccess";

export const AUTH_RETURN_PATH_KEY = "gll-auth-return-path";
const AUTH_LINK_SESSION_KEY = "gll-auth-link-session";

type LinkProvider = "google" | "discord";
type PendingLink = {
  accessToken: string;
  refreshToken: string;
  providerToken?: string;
  userId: string;
  provider: LinkProvider;
};

export const getOAuthCallbackUrl = () => {
  const language = window.location.pathname.match(/^\/limbus\/(ru|en)(?:\/|$)/)?.[1] || "en";
  return `${window.location.origin}/limbus/${language}/`;
};

export const beginAccountLink = async (session: Session, provider: LinkProvider, redirectTo: string) => {
  const pending: PendingLink = {
    accessToken: session.access_token,
    refreshToken: session.refresh_token,
    providerToken: session.provider_token || undefined,
    userId: session.user.id,
    provider
  };
  sessionStorage.setItem(AUTH_LINK_SESSION_KEY, JSON.stringify(pending));
  const result = await supabase.auth.signInWithOAuth({
    provider,
    options: {
      redirectTo,
      scopes: provider === "discord" ? "identify email guilds.members.read" : undefined,
      queryParams: provider === "discord" ? { prompt: "consent" } : undefined
    }
  });
  if (result.error) sessionStorage.removeItem(AUTH_LINK_SESSION_KEY);
  return result;
};

let pendingCompletion: Promise<Session> | null = null;

const completeAccountLink = async (session: Session) => {
  const saved = sessionStorage.getItem(AUTH_LINK_SESSION_KEY);
  if (!saved) return session;
  if (pendingCompletion) return pendingCompletion;

  pendingCompletion = (async () => {
    const pending = JSON.parse(saved) as PendingLink;
    if (pending.userId === session.user.id) {
      sessionStorage.removeItem(AUTH_LINK_SESSION_KEY);
      return session;
    }

    if (pending.provider === "discord") await verifyDiscordAccess(session);
    const { error } = await supabase.functions.invoke("merge-accounts", {
      body: { targetAccessToken: pending.accessToken }
    });
    if (error) throw error;

    sessionStorage.removeItem(AUTH_LINK_SESSION_KEY);
    const restored = await supabase.auth.setSession({
      access_token: pending.accessToken,
      refresh_token: pending.refreshToken
    });
    if (restored.error || !restored.data.session) throw restored.error || new Error("Could not restore linked account");
    const refreshed = await supabase.auth.refreshSession({ refresh_token: pending.refreshToken });
    if (refreshed.error || !refreshed.data.session) throw refreshed.error || new Error("Could not refresh linked account");
    if (pending.providerToken) {
      await verifyDiscordAccess({ ...refreshed.data.session, provider_token: pending.providerToken });
    }
    return refreshed.data.session;
  })();

  try {
    return await pendingCompletion;
  } finally {
    pendingCompletion = null;
  }
};

export const useAuthSession = () => {
  const [session, setSession] = useState<Session | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    let mounted = true;
    const applySession = async (nextSession: Session | null) => {
      if (!mounted) return;
      let resolvedSession = nextSession;
      try {
        if (nextSession) resolvedSession = await completeAccountLink(nextSession);
      } catch (linkError) {
        sessionStorage.removeItem(AUTH_LINK_SESSION_KEY);
        if (mounted) setError(linkError instanceof Error ? linkError.message : "Could not link accounts");
      }
      if (!mounted) return;
      setSession(resolvedSession);
      setLoading(false);
      if (!resolvedSession) return;
      const returnPath = sessionStorage.getItem(AUTH_RETURN_PATH_KEY);
      if (!returnPath?.startsWith("/limbus/")) return;
      sessionStorage.removeItem(AUTH_RETURN_PATH_KEY);
      if (window.location.pathname !== returnPath) window.location.replace(`${window.location.origin}${returnPath}`);
    };

    localStorage.removeItem(AUTH_RETURN_PATH_KEY);
    const oauthError = new URLSearchParams(window.location.search).get("error_description");
    if (oauthError) setError(oauthError);

    supabase.auth.getSession().then(({ data, error: sessionError }) => {
      if (sessionError && mounted) setError(sessionError.message);
      void applySession(data.session);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, nextSession) => {
      void applySession(nextSession);
    });
    return () => {
      mounted = false;
      subscription.unsubscribe();
    };
  }, []);

  return { session, user: session?.user as User | undefined, loading, error };
};
