import { ChekOption, Option } from "../componentslimbus/mirror-dungeon/events/option/MDEventOption";
import { MDEvent } from "../store/reducers/md-event-interface";
import { MDGift } from "../store/reducers/md-gift-interface";
import { FilterInterface } from "../store/reducers/filter-reducer";
import { extractInlineTraits } from "../componentslimbus/entity-full-info/traits";

export const isEventFilterMatching = (
    filterState: FilterInterface,
    searchValue:string, 
    event:MDEvent,
    locale:string,
    gifts:MDGift[] = []) =>{
    const {abnoEN,abnoRU,choiceEN,choiceRU} = event;
    const normalizedSearch = searchValue.toLocaleLowerCase();

    const name = (locale  === "ru") ? abnoRU : abnoEN;

    const option = (locale  === "ru") ? choiceRU as Option : choiceEN as Option;

    let matchesSearch = name.toLowerCase().includes(normalizedSearch);

    const eventGiftIds = new Set([
      ...getGiftIds(choiceEN),
      ...getGiftIds(choiceRU),
    ]);

    if (!matchesSearch && gifts.some(gift =>
      eventGiftIds.has(gift.id) &&
      [gift.nameRU, gift.nameEN].some(giftName =>
        giftName?.toLocaleLowerCase().includes(normalizedSearch)
      )
    )) matchesSearch = true;
    
    const stack = getTextAndOptionsKeys(option);

    for(let i = 0 ; i < stack.length && !matchesSearch;i++){
        if (
            stack[i]
            .toLowerCase()
            .includes(
                normalizedSearch
            )
        ) matchesSearch = true;
    }
    if (!matchesSearch) {
      matchesSearch = extractInlineTraits(event)
        .some(trait => trait.toLocaleLowerCase().includes(normalizedSearch));
    }
    if (!matchesSearch) return false;

    const activeTraits = Object.keys(filterState.types.traits || {}).filter(trait => filterState.types.traits[trait]);
    if (activeTraits.length) {
      const eventTraits = new Set(extractInlineTraits(event));
      if (!activeTraits.every(trait => eventTraits.has(trait))) return false;
    }
    return true;
}

function getGiftIds(value: unknown): string[] {
  if (Array.isArray(value)) {
    return value.flatMap(getGiftIds);
  }
  if (!value || typeof value !== "object") return [];

  return Object.entries(value).flatMap(([key, nestedValue]) => {
    if (key === "gift_id") {
      if (typeof nestedValue === "string") return [nestedValue];
      if (Array.isArray(nestedValue)) {
        return nestedValue.filter((id): id is string => typeof id === "string");
      }
      return [];
    }
    return getGiftIds(nestedValue);
  });
}

function getTextAndOptionsKeys(option: Option|ChekOption): string[] {
  let textsAndKeys: string[] = [];

  if (option.options) {
    textsAndKeys = textsAndKeys.concat(Object.keys(option.options));
  }
  if (option.result) {
    textsAndKeys.push(option.result);
  }
  if (option.options) {
    Object.values(option.options).forEach((nestedOption) => {
      textsAndKeys = textsAndKeys.concat(getTextAndOptionsKeys(nestedOption));
    });
  }

  if (option.combat_encounter?.result) {
    textsAndKeys.push(option.combat_encounter.result);
  }

  if (option.check_passed) {
    const {result,check_failed,check_passed,options,combat_encounter} = option.check_passed;
    if (combat_encounter?.result) {
      textsAndKeys.push(combat_encounter.result);
    }
    if (result) {
      textsAndKeys.push(result);
    }
    if(options){
      textsAndKeys.concat(Object.keys(options));
      Object.values(options).forEach((nestedOption) => {
        textsAndKeys = textsAndKeys.concat(getTextAndOptionsKeys(nestedOption));
      });
    }
    if(check_failed){
      textsAndKeys = textsAndKeys.concat(getTextAndOptionsKeys(check_failed));
    }
    if(check_passed){
      textsAndKeys = textsAndKeys.concat(getTextAndOptionsKeys(check_passed));
    }
  }

  if (option.check_failed) {
    const {result,check_failed,check_passed,options,combat_encounter} = option.check_failed;
    if (combat_encounter?.result) {
      textsAndKeys.push(combat_encounter.result);
    }
    if (result) {
      textsAndKeys.push(result);
    }
    if(options){
      textsAndKeys.concat(Object.keys(options));
      Object.values(options).forEach((nestedOption) => {
        textsAndKeys = textsAndKeys.concat(getTextAndOptionsKeys(nestedOption));
      });
    }
    if(check_failed){
      textsAndKeys = textsAndKeys.concat(getTextAndOptionsKeys(check_failed));
    }
    if(check_passed){
      textsAndKeys = textsAndKeys.concat(getTextAndOptionsKeys(check_passed));
    }
  }

  return textsAndKeys;
}
