import React, { useEffect, useRef } from "react";
import { useTranslation } from "react-i18next";
import { useQueryClient } from "react-query";
import { useDispatch } from "react-redux";
import { useParams } from "react-router-dom";
import { useTypedSelector } from "../../hooks/useTypedSelector";
import { EGOInterface } from "../../store/reducers/ego-reducer";
import { IdentityInterface } from "../../store/reducers/ids-reducer";
import { searchChangeTargetRefAction } from "../../store/reducers/search-reducer";
import { isFilterMatching } from "../../tools/isFilterMatching";
import { compareEntitiesByRarityAndDate } from "../../tools/compareEntitiesByRarityAndDate";
import { ItemEntity } from "../item-entity/ItemEntity";
import { TierBar } from "./tier-bar/TierBar";
import { StatusesInterface } from "../../store/reducers/statuses-reducer";
import "./TierList.css";

type TRatings = {
    [key: string]: {
        data: React.ReactElement[],
        description: string
    }
}

export const TierList: React.FC = () => {
    const ids = useQueryClient().getQueryData("identities") as IdentityInterface[] | null;
    const ego = useQueryClient().getQueryData("ego") as EGOInterface[] | null;
    const statuses = useQueryClient().getQueryData('statuses') as StatusesInterface[];
    const { t, i18n } = useTranslation();
    const filterState = useTypedSelector(state => state.filterReducer);
    const searchState = useTypedSelector(state => state.searchReducer);
    const params = useParams();
    const type = params["type"] || "";
    const containerRef = useRef(null);
    const dispatch = useDispatch();

    useEffect(() => {
        searchChangeTargetRefAction(dispatch, containerRef);
    }, [dispatch]);

    // Утилита для получения ПЕРВОГО валидного тира из строки или массива
    const getFirstValidTier = (tier: string | string[] | undefined | null, validKeys: string[]): string | null => {
        if (!tier) return null;
        
        let tiers: string[] = [];
        if (Array.isArray(tier)) {
            tiers = tier;
        } else if (typeof tier === "string") {
            tiers = tier.includes(",") ? tier.split(",").map(t => t.trim()) : [tier];
        }

        // Берем первый тир, который есть в списке наших ключей категорий (SSS, SS, S, A, B, C, Test)
        return tiers.find(t => t && validKeys.includes(t)) || null;
    };

    const setupEGO = (ratings: TRatings) => {
        const validKeys = Object.keys(ratings);
        ego?.forEach((item: EGOInterface, index) => {
            const firstTier = getFirstValidTier(item.egoTier, validKeys);
            
            if (firstTier && isFilterMatching(filterState, searchState, item, i18n.language, statuses)) {
                ratings[firstTier].data.push(<ItemEntity key={index} entity={item} />);
            }
        });

        Object.keys(ratings).forEach(key => {
            ratings[key].data.sort((a, b) => {
                const itemA = (a.props.entity as EGOInterface);
                const itemB = (b.props.entity as EGOInterface);
                return compareEntitiesByRarityAndDate(itemA, itemB);
            });
        });
        return ratings;
    };

    const setupIds = (ratings: TRatings) => {
        const validKeys = Object.keys(ratings);
        ids?.forEach((item: IdentityInterface, index) => {
            const firstTier = getFirstValidTier(item.idTier, validKeys);
            
            if (firstTier && isFilterMatching(filterState, searchState, item, i18n.language, statuses)) {
                ratings[firstTier].data.push(<ItemEntity key={index} entity={item} />);
            }
        });

        Object.keys(ratings).forEach(key => {
            ratings[key].data.sort((a, b) => {
                const itemA = (a.props.entity as IdentityInterface);
                const itemB = (b.props.entity as IdentityInterface);
                return compareEntitiesByRarityAndDate(itemA, itemB);
            });
        });
        return ratings;
    };

    const setupItems = (paramType: string) => {
        // Здесь перечислены все возможные категории. Логика getFirstValidTier будет опираться на эти ключи.
        const ratings: TRatings = {
            "SSS": { data: [], description: t(`TierList.description.${paramType}.SSS`) },
            "SS": { data: [], description: t(`TierList.description.${paramType}.SS`) },
            "S": { data: [], description: t(`TierList.description.${paramType}.S`) },
            "A": { data: [], description: t(`TierList.description.${paramType}.A`) },
            "B": { data: [], description: t(`TierList.description.${paramType}.B`) },
            "C": { data: [], description: t(`TierList.description.${paramType}.C`) },
            "D": { data: [], description: t(`TierList.description.${paramType}.D`) },
            "Test": { data: [], description: t(`TierList.description.${paramType}.Test`) },
        };
        return paramType === "ego" ? setupEGO(ratings) : setupIds(ratings);
    };

    const ratings = setupItems(type);

    return (
        <section ref={containerRef} className="tier-list-container">
            <section className={["tier-list", "tier-list--ego-ids"].join(" ")}>
                <h2 className="tier-list-name">
                    {t(`TierList.name.${type}`) + ` (${Object.values(ratings).reduce((a, b) => a + b.data.length, 0)})`}
                </h2>
                {Object.entries(ratings).map(([key, val]) => val.data.length > 0 && (
                    <TierBar count={val.data.length} rating={key} description={val.description} key={key}>
                        <React.Fragment>{val.data}</React.Fragment>
                    </TierBar>
                ))}
            </section>
        </section>
    );
};
