import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { SkillCoinDescription } from "../../guides/text-formatter/SkillCoinDescription";
import { EyeClosedSVG } from '../../svg/EyeClosedSVG';
import { EyeOpenedSVG } from '../../svg/EyeOpenedSVG';
import './TierListDisclaimer.css';

type TDisclaimerVisibility = "show" | "hide";

export const TierListDisclaimer:React.FC = () => {
    const {t,i18n} = useTranslation();
    const getStoredDisclaimer = () =>{
      const disclaimerVisibility = localStorage.getItem("tier-list-disclaimer-visibility");
      return disclaimerVisibility === "hide" ? "hide" : "show";
    }
    const [disclaimerVisibility, setDisclaimerVisibility] = useState<TDisclaimerVisibility>(getStoredDisclaimer());

    const handleDisclaimerVisibility = () => {
        const newDisclaimerVisibility = disclaimerVisibility === "show" ? "hide" : "show";
        localStorage.setItem("tier-list-disclaimer-visibility",newDisclaimerVisibility);
        setDisclaimerVisibility(newDisclaimerVisibility);
    }
    const descriptions:Record<string,string> = {
        "en": `Only the tier of Identity/EGO matters. Within tiers, the position of Identities/EGO is NOT a ranking of strength.<br/>Identities are rated, taking into account team building possibilities and E.G.O synergies.<br/>If an Identity or E.G.O is specifically designed to significantly enhance another particular Identity or E.G.O, an additional tier is shown that takes this synergy into account.<br/>Identities/EGO are rated with maximum improvement.<br/>When assessing identity/ego, Mirror Dungeon is NOT a criterion for evaluation.<br/><br/>If you disagree with the position of Identity/EGO in the Tier List, then you can go to our <a class="disclaimer-link" href="https://discord.gg/BGpmmqknWE">Discord</a> server.<br/>We reserve the right not to respond to your messages regarding Tier Lists outside of our Discord server.<br/>We ask you to compose more constructive and detailed messages, otherwise, we may misunderstand you.<br/><br/>Calculations of minimum and maximum damage were made with Resistance to Sins and Damage Types equal to x1.<br/>Minimum damage is calculated without conditional effects but with all flipped coins (in the case of negative coins, the opposite) and guaranteed effects.<br/>Maximum damage is calculated with all flipped coins (in the case of negative coins, the opposite) and with all effects from skills and battle passive, except for the <span class="condition--green">[On Kill]</span> conditional effect; also, Identities with the #poise# status always deal Critical Strikes.<br/>For Identities with Res., it is considered equal to the maximum size of the team in the current 'Refraction Railway'.<br/>All statuses dealing damage are taken into account when calculating damage.`,
        "ru": `Важен только тир идентичности/ЭГО. Внутри тиров положение идентичностей/ЭГО НЕ является разделением по силе.<br/>Идентичности оцениваются с учётом возможности сборки команд и синергии с ЭГО.<br/>Если идентичность или ЭГО предназначены для значительного усиления другой конкретной идентичности или ЭГО, дополнительно указывается тир с учётом данной синергии.<br/>Иденичности/ЭГО оцениваются при максимальном улучшении.<br/>При оценивании идентичности/ЭГО, Зеркальное Подземелье НЕ является критерием для оценки<br/><br/>Если вы недовольны положением идентичности/ЭГО в тирлисте, то можете пройти на наш <a class="disclaimer-link" href="https://discord.gg/BGpmmqknWE">Дискорд</a> сервер.<br/>Мы оставляем за собой право не отвечать на ваши сообщения по тирлистам вне нашего дискорд сервера.<br/>Просим составлять более конструктивные и развёрнутые сообщения, иначе мы можем не верно вас понять.<br/><br/>Расчеты минимального и максимального урона производились при спротивлении к грехам и типам урона равным х1.<br/>Минимальный урон считается без эффектов с условием, но со всеми выпавшими монетками(для отрицательных монет наоборот) и гарантированными эффектами.<br/>Максимальный урон считается со всеми выпавшими монетками(для отрицательных монет наоборот) и со всеми эффектами от скилла и боевой пассивки, кроме эффекта с условием <span class="condition--green">[при убийстве]</span>, также идентичности со статусом #poise# всегда наносят критические попадания.<br/>У идентичностей с усилением от рез. он считается равным максимальному размеру команды в текущей "Железной дороге преломления" (Рельсе).<br/>Все статусы, наносящие урон, учтены при подсчёте урона.`,
    }
  return (
    <div role="contentinfo" aria-label="Disclaimer" aria-labelledby="disclaimer-heading" className="TierListDisclaimer">
        <h2 className="TierListDisclaimer-heading">
            {t("TierListDisclaimer.header")} 
            <button className="filters-show-btn" onClick={handleDisclaimerVisibility}>
                {
                    disclaimerVisibility === "show" ? <EyeOpenedSVG/> : <EyeClosedSVG/>
                }
            </button>

        </h2>
        {
        disclaimerVisibility === "show" && <SkillCoinDescription description={descriptions[i18n.language]||''}/>
        }
   
    </div>
  );
};