import React, { useState, useMemo } from 'react'; 
import { supabase } from '../../../tools/supabaseClient'; // Добавлен импорт клиента Supabase
import { useTranslation } from 'react-i18next';
import { useQueryClient } from 'react-query';
import { useDispatch } from 'react-redux';
import { EGOInterface } from '../../../store/reducers/ego-reducer';
import { setMobileModalTrigger } from '../../../store/reducers/mobile-modal-reducer';
import { SkillCoinDescription } from "../../guides/text-formatter/SkillCoinDescription";
import { StatusesInterface } from '../../../store/reducers/statuses-reducer';
import { getStatusesEntityList } from '../../../tools/getStatusesEntityList';
import { TooltipMobile } from '../../tooltip-mobile/TooltipMobile';
import "./EntityFullInfoEGO.css";

interface IEntityFullInfoProps {
    ego: EGOInterface;
    statusUnik?: string;
    uptieValue: number;
}

interface AdminField {
    label: string;
    key: string;
    type: 'text' | 'number';
}

interface AdminTab {
    id: string;
    title: string;
    fields: AdminField[];
}

// Конфигурация вкладок для ЭГО панели управления
const ADMIN_TABS: AdminTab[] = [
  {
    id: 'basic',
    title: 'Основная информация',
    fields: [
      { label: 'Image URL', key: 'imgUrl', type: 'text' },
      { label: 'Name EN', key: 'nameEN', type: 'text' },
      { label: 'Name RU', key: 'nameRU', type: 'text' },
      { label: 'Sinner', key: 'sinner', type: 'text' },
      { label: 'Rarity', key: 'rarity', type: 'text' },
      { label: 'Season', key: 'season', type: 'text' },
      { label: 'Release Date', key: 'releaseDate', type: 'text' },
      { label: 'Is New', key: 'isNew', type: 'text' },
      { label: 'EGO Tier', key: 'egoTier', type: 'text' },
      { label: 'Status Unik', key: 'statusUnik', type: 'text' },
      { label: 'Traits', key: 'traits', type: 'text' }
    ]
  },
  {
    id: 'skills_meta',
    title: 'Характеристики навыков',
    fields: [
      { label: 'Damage', key: 'damage', type: 'text' },
      { label: 'EGO Sin', key: 'egoSin', type: 'text' },
      { label: 'Damage Type', key: 'dmgType', type: 'text' },
      { label: 'Syn IDS', key: 'synIDS', type: 'text' }
    ]
  },
  {
    id: 'coin_mechanics',
    title: 'Механика монеток',
    fields: [
      { label: 'Basic Coin', key: 'basicCoin', type: 'text' },
      { label: 'Growth Per Coin', key: 'growthPerCoin', type: 'text' },
      { label: 'Max Coin Value', key: 'maxCoinValue', type: 'text' },
      { label: 'Clash Coin Value', key: 'clashCoinValue', type: 'text' },
      { label: 'Count Coin', key: 'countCoin', type: 'text' },
      { label: 'Weight Coin', key: 'weightCoin', type: 'text' }
    ]
  },
  {
    id: 'costs_resists',
    title: 'Стоимость и Резисты',
    fields: [
      { label: 'Sin Cost (Массив)', key: 'SinCost', type: 'text' },
      { label: 'Sanity (Массив)', key: 'sanity', type: 'text' },
      { label: 'EGO Resists (Массив)', key: 'egoResists', type: 'text' }
    ]
  },
  {
    id: 'localization',
    title: 'Названия и Тексты',
    fields: [
      { label: 'Skill Names EN', key: 'nameSkillEN', type: 'text' },
      { label: 'Skill Names RU', key: 'nameSkillRU', type: 'text' },
      { label: 'Passive Name EN', key: 'namePassiveEN', type: 'text' },
      { label: 'Passive Name RU', key: 'namePassiveRU', type: 'text' },
      { label: 'Passive Desc EN', key: 'descriptionPassiveEN', type: 'text' },
      { label: 'Passive Desc RU', key: 'descriptionPassiveRU', type: 'text' }
    ]
  },
  {
    id: 'coins_desc',
    title: 'Описания Монеток (Coin)',
    fields: [
      { label: 'Coin EN 2', key: 'CoinEN2', type: 'text' },
      { label: 'Coin RU 2', key: 'CoinRU2', type: 'text' },
      { label: 'Coin EN 3', key: 'CoinEN3', type: 'text' },
      { label: 'Coin RU 3', key: 'CoinRU3', type: 'text' },
      { label: 'Coin EN 4', key: 'CoinEN4', type: 'text' },
      { label: 'Coin RU 4', key: 'CoinRU4', type: 'text' },
      { label: 'Coin EN 5', key: 'CoinEN5', type: 'text' },
      { label: 'Coin RU 5', key: 'CoinRU5', type: 'text' }
    ]
  }
];
const resMap: { [key: string]: string } = {
    'ineff': '[x0.5]',
    'normal': '[x1]',
    'fatal': '[x2]',
    'endure': '[x0.75]',
};

const extractStatusIds = (text: string): string[] => {
    if (!text) return [];
    const regex = /#([^#\s{}]+)(?:\{[^}]*\})?#/g;
    const ids: string[] = [];
    let match;
    while ((match = regex.exec(text)) !== null) {
        ids.push(match[1]);
    }
    return ids;
};

export const EntityFullInfoEGO: React.FC<IEntityFullInfoProps> = ({ ego, statusUnik, uptieValue }) => {
    const { sinner, imgUrl, season, egoTier, rarity, egoResists, releaseDate, synIDS } = ego;
    const { t, i18n } = useTranslation();
    const lang = i18n.language.toUpperCase();
    const dispatch = useDispatch();
    const queryClient = useQueryClient();
    const statuses = queryClient.getQueryData('statuses') as StatusesInterface[];

    const rarityStyled = rarity.replaceAll("O", "Ø");
    const sinsList = ["wrath", "lust", "sloth", "glut", "gloom", "pride", "envy"];

    // Стейты админ-панели
    const isAdmin = false;
    const [isAdminPanelOpen, setIsAdminPanelOpen] = useState(false);
    const [activeTab, setActiveTab] = useState('general');
    const [adminFormData, setAdminFormData] = useState<any>({});

    // Проверка прав (адаптировано под ваш первоначальный supabase-метод)
    // Открытие единой админ-панели
    const openAdminPanel = async () => {
        if (!isAdmin) return;
        
        try {
            const { data, error } = await supabase
                .from('ego_new')
                .select('*')
                .eq('imgUrl', ego.imgUrl)
                .single();

            if (error) throw error;

            const initialForm: any = data ? { ...data } : { ...ego };
            
            // Превращаем массивы/объекты в JSON-строки для редактирования
            ADMIN_TABS.forEach((tab) => {
                tab.fields.forEach((f) => {
                    if (Array.isArray(initialForm[f.key]) || (initialForm[f.key] && typeof initialForm[f.key] === 'object')) {
                        initialForm[f.key] = JSON.stringify(initialForm[f.key]);
                    }
                });
            });
            
            setAdminFormData(initialForm);
            setIsAdminPanelOpen(true);
        } catch (err: any) {
            alert('Ошибка загрузки сырых данных из базы: ' + err.message);
            
            const initialForm: any = { ...ego };
            ADMIN_TABS.forEach((tab) => {
                tab.fields.forEach((f) => {
                    if (Array.isArray(initialForm[f.key])) {
                        initialForm[f.key] = JSON.stringify(initialForm[f.key]);
                    }
                });
            });
            setAdminFormData(initialForm);
            setIsAdminPanelOpen(true);
        }
    };

    const handleFormChange = (key: string, value: any) => {
        setAdminFormData((prev: any) => ({ ...prev, [key]: value }));
    };

    // Сохранение изменений всей формы
    const saveAdminData = async () => {
    try {
        const dataToSave = { ...adminFormData };
        
        // --- НАЧАЛО ТРАНСФОРМАЦИИ ДАТЫ ДЛЯ БАЗЫ ---
        if (dataToSave.releaseDate) {
            const dateStr = String(dataToSave.releaseDate).trim();
            let parsedDate: Date | null = null;

            // Если ввели в формате ГГГГ-ММ-ДД (например, 2026-06-25)
            if (/^\d{4}-\d{2}-\d{2}$/.test(dateStr)) {
                parsedDate = new Date(dateStr);
            } 
            // Если ввели в формате ДД.ММ.ГГГГ (например, 25.06.2026)
            else if (/^\d{2}\.\d{2}\.\d{4}$/.test(dateStr)) {
                const [day, month, year] = dateStr.split('.');
                parsedDate = new Date(`${year}-${month}-${day}`);
            }

            if (parsedDate && !isNaN(parsedDate.getTime())) {
                const excelStartDate = new Date(1899, 11, 30);
                const millisecondsPerDay = 24 * 60 * 60 * 1000;
                // Считаем разницу в днях
                const diffDays = Math.floor((parsedDate.getTime() - excelStartDate.getTime()) / millisecondsPerDay);
                dataToSave.releaseDate = diffDays;
            } else if (isNaN(Number(dateStr))) {
                // Если это и не дата, и не чистое число дней, ставим 0 во избежание краша
                dataToSave.releaseDate = 0;
            } else {
                // Если админ вручную ввёл сразу число дней (например, 46198)
                dataToSave.releaseDate = Number(dateStr);
            }
        }
            
            ADMIN_TABS.forEach((tab) => {
                tab.fields.forEach((f) => {
                    if (f.type === 'number') {
                        dataToSave[f.key] = dataToSave[f.key] === '' ? 0 : Number(dataToSave[f.key]);
                    }
                    if (typeof dataToSave[f.key] === 'string' && (dataToSave[f.key].trim().startsWith('[') || dataToSave[f.key].trim().startsWith('{'))) {
                        try {
                            dataToSave[f.key] = JSON.parse(dataToSave[f.key]);
                        } catch (e) {
                            // Оставляем строкой, если это не валидный JSON
                        }
                    }
                });
            });

            const { error } = await supabase
                .from('ego_new')
                .update(dataToSave)
                .eq('imgUrl', ego.imgUrl);

            if (error) throw error;

            setIsAdminPanelOpen(false);
            queryClient.invalidateQueries('ego');
            alert('Данные EGO успешно сохранены!');
        } catch (error: any) {
            alert('Ошибка сохранения: ' + error.message);
        }
    };

    const getParamValueByUptie = (param: any[], indexInUptie: number): number => {
        if (!param || param.length === 0) return 0;
        const isFlatArray = !Array.isArray(param[0]);
        if (isFlatArray) {
            return param[indexInUptie] !== undefined ? Number(param[indexInUptie]) || 0 : 0;
        }
        const uptieData = param[uptieValue - 1] !== undefined ? param[uptieValue - 1] : param[param.length - 1];
        if (!Array.isArray(uptieData)) return 0;
        return uptieData[indexInUptie] !== undefined ? Number(uptieData[indexInUptie]) || 0 : 0;
    };

    const awakeningSanity = getParamValueByUptie(ego.sanity, 0);
    const corrosionSanity = getParamValueByUptie(ego.sanity, 1);
    const overclockSanity = Math.round(corrosionSanity * 1.5);

    const [imgID, setImgID] = useState('1');

    const currentDescription = useMemo(() => {
        let effectiveUptie = uptieValue < 2 ? 2 : uptieValue;
        const getKey = (val: number) => `Coin${lang}${val}` as keyof EGOInterface;
        
        let desc = ego[getKey(effectiveUptie)] as string;
        if (effectiveUptie === 5 && (!desc || desc.trim() === "")) {
            desc = ego[getKey(4)] as string;
        }
        return desc || (ego[getKey(2)] as string) || "";
    }, [ego, uptieValue, lang]);

    const status = useMemo(() => {
        const passiveDesc = ego[`descriptionPassive${lang}` as keyof typeof ego] as string || '';
        const allTexts = [currentDescription, passiveDesc];
        const taggedIds = allTexts.flatMap(text => extractStatusIds(text));
        return getStatusesEntityList([...allTexts, ...taggedIds]);
    }, [ego, lang, currentDescription]);

    const toggleImgID = () => setImgID(prevID => (prevID === '1' ? '2' : '1'));

    function updateStatusWithFuseStatuses(allStatuses: StatusesInterface[], status: { [key: string]: number }): { [key: string]: number } {
        const updatedStatus = { ...status };
        for (const id of Object.keys(status)) {
            const foundStatus = allStatuses.find(s => s.id === id);
            if (foundStatus && foundStatus.fuse_statuses) {
                const fuseId = foundStatus.fuse_statuses;
                if (!(fuseId in updatedStatus)) {
                    updatedStatus[fuseId] = 0;
                }
            }
        }
        return updatedStatus;
    }

    const fuseStatuses = useMemo(() => updateStatusWithFuseStatuses(statuses, status), [statuses, status]);

    const filteredStatusKeys = useMemo(() => {
        if (!fuseStatuses) return [];
        if (!statusUnik) return Object.keys(fuseStatuses).filter(s => fuseStatuses[s] > 0);

        const [addPart, removePart] = statusUnik.split('|').map(part => part.trim());
        const statusesToAdd = addPart ? addPart.split('#').filter(s => s.trim()).map(s => s.trim().toLowerCase()) : [];
        const statusesToRemove = removePart ? removePart.split('#').filter(s => s.trim()).map(s => s.trim().toLowerCase()) : [];

        let filtered = Object.keys(fuseStatuses).filter(s => {
            const lower = s.toLowerCase();
            return !statusesToRemove.includes(lower) && fuseStatuses[s] > 0;
        });

        statusesToAdd.forEach(statusToAdd => {
            const foundStatus = statuses.find(st => st.id.toLowerCase() === statusToAdd);
            if (foundStatus) {
                const fullStatusId = foundStatus.id;
                if (!filtered.includes(fullStatusId)) filtered.push(fullStatusId);
            } else {
                if (!filtered.includes(statusToAdd)) filtered.push(statusToAdd);
            }
        });
        return filtered;
    }, [fuseStatuses, statusUnik, statuses]);

    const formateDate = (date: number) => {
        const excelStartDate = new Date(1899, 11, 30);
        const millisecondsPerDay = 24 * 60 * 60 * 1000;
        const newDate = new Date(excelStartDate.getTime() + date * millisecondsPerDay);
        const month = `${newDate.getMonth() + 1}`.padStart(2, '0');
        const day = `${newDate.getDate()}`.padStart(2, '0');
        return `${day}.${month}.${newDate.getFullYear()}`;
    };

    const shouldShowSwapButton = !(imgUrl.startsWith('ego_') && parseInt(imgUrl.replace('ego_', ''), 10) >= 1 && parseInt(imgUrl.replace('ego_', ''), 10) <= 12);

    return (
        <section className={'entityFullInfo-entity'}>
            <article className={"entityFullInfo-img"}>
                <div className="entityFullInfo-rarity">{rarityStyled}</div>
                <img className="entityFullInfo-sinner" src={`${process.env.PUBLIC_URL}/images/sinners-icons/${sinner}.webp`} alt={`${sinner}`} />

                <div className={"shadow"}>
                    <img src={`${process.env.PUBLIC_URL}/images/ego-profiles/${imgUrl}.${imgID}_profile.webp`} alt={`${imgUrl}`} />
                </div>

                {shouldShowSwapButton && (
                    <button onClick={toggleImgID} className="image-swap-button">
                        {t(imgID === '1' ? "EntityFullInfoEGO.switchImage1" : "EntityFullInfoEGO.switchImage2")}
                    </button>
                )}

                <div 
                    className={`entityFullInfo-tier-container entityFullInfo-tier-${egoTier}`}
                    onClick={isAdmin ? openAdminPanel : undefined}
                    style={{ cursor: isAdmin ? 'pointer' : 'default' }}
                >
                    {egoTier?.split(',').map(tier => tier.trim()).filter(Boolean).map((tier, index) => (
                        <div key={index} className={`entityFullInfo-tier entityFullInfo-tier-${tier}`}>
                            {tier}
                        </div>
                    ))}
                </div>
            </article>

            {/* Вся правая панель со статами теперь открывает общую админку по клику в режиме админа */}
            <div className='entityFullInfo-stats-container' onClick={isAdmin ? openAdminPanel : undefined} style={{ cursor: isAdmin ? 'pointer' : 'default' }}>
                <article className={"entityFullInfo-stats"}>
                    <h2>{t("EntityFullInfoIdentity.info")}</h2>
                    <div className={`entityFullInfo-season entityFullInfo-season-${season[0][0] === 'w' ? 'w' : (typeof season[0] === 'string' ? season[0].replace(/^i-/, 's-') : '1')}`}>
                        {t(`EntityFullInfoIdentity.season.${Array.isArray(season) ? season[0] : season}`)}
                        {season[1] && ` [${t(`EntityFullInfoIdentity.season.${season[1]}`)}]`}
                    </div>
                    <div className={"entityFullInfo-release"}>
                        {t('EntityFullInfoIdentity.release')} &nbsp;
                        <span className="date">{formateDate(releaseDate)}</span>
                    </div>
                </article>

                {filteredStatusKeys.length > 0 && (
                    <article className={"entityFullInfo-stats"}>
                        <h2>{t("EntityFullInfoEGO.statuses")}</h2>
                        <ul className='statuses-list'>
                            {filteredStatusKeys.map((s, index) => {
                                const statusData = statuses.find(st => st.id === s);
                                if (!statusData) return null;
                                const description = statusData[`description${lang}` as keyof typeof statusData] as string || '';
                                const name = statusData[`name${lang}` as keyof typeof statusData] as string || '';
                                const imgHTML = <img src={`${process.env.PUBLIC_URL}/images/tags/${s}.webp`} alt={`${s}`} />;
                                const mobileStatusHTML = <TooltipMobile text={description} header={name} image={imgHTML} />;
                                
                                return (
                                    <li onClick={(e) => { e.stopPropagation(); setMobileModalTrigger(dispatch, mobileStatusHTML); }} key={index} className='tooltip-container '>
                                        {imgHTML}
                                        <span className='entityFullInfo-tooltip '>
                                            {t("SkillCoinDescription.clickToSeeDescription")}
                                        </span>
                                    </li>
                                );
                            })}
                        </ul>
                    </article>
                )}

                <article className={"entityFullInfo-stats"}>
                    <h2>{t("EntityFullInfoEGO.cost")}</h2>
                    <ul className='ego-cost-list'>
                        <li>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
                                <img src={`${process.env.PUBLIC_URL}/images/general/sanity.webp`} alt="sanity" />
                                {corrosionSanity !== 0 && <img src={`${process.env.PUBLIC_URL}/images/general/overcoc.webp`} alt="overclock" />}
                            </div>
                            <span style={{ marginLeft: '10px' }}>
                                {awakeningSanity}
                                {corrosionSanity !== 0 && (
                                    <>
                                        <> | <span style={{ color: "red" }}>{corrosionSanity}</span></>
                                        <> | <span style={{ color: "#ff9800" }}>{overclockSanity}</span></>
                                    </>
                                )}
                            </span>
                        </li>
                        {sinsList.map((sin, index) => {
                            const activeSinsCount = ego.SinCost.filter(c => c > 0).length;
                            if (activeSinsCount >= 6 && index > 2) return null;
                            const curr = ego.SinCost[index];
                            if (!curr || curr === 0) return null;

                            return (
                                <li key={index}>
                                    <img src={`${process.env.PUBLIC_URL}/images/sins/${sin}.webp`} alt={sin} />
                                    <span>
                                        {curr}
                                        {ego.imgUrl && !ego.imgUrl.match(/ego_[1-9]$|ego_1[0-2]$/) && (
                                            <> | <span style={{ color: "red" }}>{Math.ceil(curr * 1.5)}</span></>
                                        )}
                                    </span>
                                </li>
                            );
                        })}
                    </ul>
                    
                    {ego.SinCost.filter(c => c > 0).length >= 6 && (
                        <ul className='ego-cost-list'>
                            {sinsList.map((sin, index) => {
                                if (index <= 2) return null;
                                const curr = ego.SinCost[index];
                                if (!curr || curr === 0) return null;
                                return (
                                    <li key={index}>
                                        <img src={`${process.env.PUBLIC_URL}/images/sins/${sin}.webp`} alt={sin} />
                                        <span>
                                            {curr} | <span style={{ color: "red" }}>{Math.ceil(curr * 1.5)}</span>
                                        </span>
                                    </li>
                                );
                            })}
                        </ul>
                    )}
                </article>

                <article className={"entityFullInfo-stats"}>
                    <h2>{t("EntityFullInfoEGO.res")}</h2>
                    <ul className='ego-resists'>
                        {egoResists.map((res, index) => {
                            if (index > 2) return null;
                            return (
                                <li key={index}>
                                    <img src={`${process.env.PUBLIC_URL}/images/sins/${sinsList[index]}.webp`} alt={sinsList[index]} />
                                    {resMap[res.toLowerCase().replace(/\s/g, "")]}
                                </li>
                            );
                        })}
                    </ul>
                    <ul className='ego-resists'>
                        {egoResists.map((res, index) => {
                            if (index <= 2) return null;
                            return (
                                <li key={index}>
                                    <img src={`${process.env.PUBLIC_URL}/images/sins/${sinsList[index]}.webp`} alt={sinsList[index]} />
                                    {resMap[res.toLowerCase().replace(/\s/g, "")]}
                                </li>
                            );
                        })}
                    </ul>
                </article>

                <article className={"entityFullInfo-stats"}>
                    <h2 className="s1yn-ego-container">{t("EntityFullInfoIdentity.synIDS")}</h2>
                    <div className="syn-ego-container">
                        {synIDS?.split(",").filter(Boolean).map((v, index) => (
                            <div key={index} className="syn-ego-item-wrapper">
                                <SkillCoinDescription description={`&${v.trim()}&`} />
                            </div>
                        ))}
                    </div>
                </article>
            </div>

            {/* МУЛЬТИТАБ ПАНЕЛЬ УПРАВЛЕНИЯ ЭГО */}
            {isAdminPanelOpen && (
                <div className="admin-modal-overlay" onClick={() => setIsAdminPanelOpen(false)}>
                    <div className="admin-modal" onClick={(e) => e.stopPropagation()}>
                        <div className="admin-modal-header">
                            Панель управления EGO: {ego.imgUrl}
                        </div>
                        <div className="admin-modal-body">
                            <div className="admin-modal-sidebar">
                                {ADMIN_TABS.map((tab) => (
                                    <button
                                        key={tab.id}
                                        className={`admin-sidebar-item ${activeTab === tab.id ? 'active' : ''}`}
                                        onClick={() => setActiveTab(tab.id)}
                                    >
                                        {tab.title}
                                    </button>
                                ))}
                            </div>
                            
                            <div className="admin-modal-content">
                                {ADMIN_TABS.find((t) => t.id === activeTab)?.fields.map((field) => (
                                    <div key={field.key} className="admin-field-group">
                                        <label>{field.label}</label>
                                        {field.key.includes('Coin') || 
                                         field.key.includes('Passive') || 
                                         field.key.includes('Cost') || 
                                         field.key.includes('sanity') || 
                                         field.key.includes('egoResists') ? (
                                            <textarea
                                                value={adminFormData[field.key] || ''}
                                                onChange={(e) => handleFormChange(field.key, e.target.value)}
                                            />
                                        ) : (
                                            <input
                                                type={field.type === 'number' ? 'number' : 'text'}
                                                value={adminFormData[field.key] || ''}
                                                onChange={(e) => handleFormChange(field.key, e.target.value)}
                                            />
                                        )}
                                    </div>
                                ))}
                            </div>
                        </div>
                        <div className="modal-actions">
                            <button className="btn-close" onClick={() => setIsAdminPanelOpen(false)}>Отмена</button>
                            <button className="btn-save" onClick={saveAdminData}>Сохранить</button>
                        </div>
                    </div>
                </div>
            )}       
        </section>
    );
};
